-- Schema for Domain: production | Business:  | Version: v1_mvm
-- Generated on: 2026-04-16 09:51:31

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `manufacturing_ecm`.`production` COMMENT 'Manages all shop floor execution, manufacturing scheduling, work orders, production order lifecycle, and real-time manufacturing operations using MES and ERP systems. Serves as the SSOT for WIP tracking, work center capacity, routing, takt time, cycle time, throughput, OEE metrics, and batch control. Covers MTO, MTS, ETO, and ATO production strategies and MRP II resource planning.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`work_center` (
    `work_center_id` BIGINT COMMENT 'Unique surrogate identifier for the work center record in the lakehouse silver layer. Serves as the primary key for all downstream joins and references.',
    `class_id` BIGINT COMMENT 'Foreign key linking to asset.class. Business justification: Work centers are classified by asset class (e.g., CNC, press, conveyor) in manufacturing ERP systems. Production planners use this daily to filter capacity by equipment class and apply class-level mai',
    `location_id` BIGINT COMMENT 'Foreign key linking to logistics.location. Business justification: Work centers are physically situated at specific plant or facility locations. This link is used by logistics planners for material routing, transport planning to the correct shop floor area, and capac',
    `activity_type_code` STRING COMMENT 'SAP Controlling activity type code (e.g., MACH, LABOR) used to allocate costs from this work center to production orders. Enables granular cost-of-goods-sold (COGS) analysis.. Valid values are `^[A-Z0-9]{1,10}$`',
    `capacity_available_hours_per_day` DECIMAL(18,2) COMMENT 'Total available production hours per day for this work center, calculated from active shifts and break schedules. Used as the baseline for capacity requirements planning (CRP) in MRP II.. Valid values are `^d{1,6}(.d{1,4})?$`',
    `capacity_category` STRING COMMENT 'Defines the primary capacity resource type tracked for this work center (machine hours, labor hours, energy units, tooling). Used in MRP II capacity requirements planning (CRP).. Valid values are `machine|labor|energy|tool|other`',
    `category_code` STRING COMMENT 'SAP work center category code (e.g., 0001 for machine, 0002 for labor) that controls which fields and formulas are active for capacity and costing. Drives MRP II planning behavior.. Valid values are `^[A-Z0-9]{1,10}$`',
    `code` STRING COMMENT 'Alphanumeric business key identifying the work center within the plant, as defined in SAP PP (field ARBPL). Used in routing operations, production orders, and MRP II capacity planning.. Valid values are `^[A-Z0-9_-]{1,20}$`',
    `control_key` STRING COMMENT 'SAP PP control key assigned to operations at this work center, determining whether operations are confirmed, printed, scheduled externally, or subject to milestone confirmation. Governs MES integration behavior.. Valid values are `^[A-Z0-9]{1,10}$`',
    `costing_formula` STRING COMMENT 'Identifier of the formula used to calculate production costs (machine costs, labor costs, overhead) for operations performed at this work center. Links to SAP CO activity types and cost rates.. Valid values are `^[A-Z0-9_]{1,30}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country where this work center is physically located. Supports multinational regulatory compliance, labor law adherence, and regional capacity reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the work center master data record was first created in the source system. Used for data lineage, audit trail, and master data governance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the local currency used in cost rate calculations and activity pricing for this work center. Supports multi-currency costing in multinational operations.. Valid values are `^[A-Z]{3}$`',
    `cycle_time_seconds` DECIMAL(18,2) COMMENT 'Standard time in seconds to complete one unit of production at this work center under normal operating conditions. Compared against takt time to identify bottlenecks and balance production lines.. Valid values are `^d{1,6}(.d{1,4})?$`',
    `efficiency_rate_percent` DECIMAL(18,2) COMMENT 'Ratio of standard time to actual time expressed as a percentage, representing how efficiently the work center converts available time into productive output. Used in capacity planning and OEE calculations.. Valid values are `^(100(.0{1,2})?|[0-9]{1,2}(.d{1,2})?)$`',
    `floor_area_sqm` DECIMAL(18,2) COMMENT 'Physical floor space occupied by the work center in square meters. Used in facility layout planning, 5S audits, and capacity expansion assessments.. Valid values are `^d{1,7}(.d{1,2})?$`',
    `hierarchy` STRING COMMENT 'Hierarchical grouping path of the work center within the plant structure (e.g., Plant A > Production Area 2 > Assembly Line 1). Used for aggregated capacity reporting and organizational drill-down in analytics.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the work center master data record. Used for incremental data loading, change tracking, and master data governance in the lakehouse silver layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `move_time_hours` DECIMAL(18,2) COMMENT 'Standard time in hours required to physically transport WIP from this work center to the next operation in the routing. Contributes to total manufacturing lead time in MRP II scheduling.. Valid values are `^d{1,6}(.d{1,4})?$`',
    `name` STRING COMMENT 'Descriptive name of the work center (e.g., CNC Machining Cell 3, Final Assembly Line A). Used in shop floor scheduling, routing, and reporting.',
    `number_of_labor_resources` STRING COMMENT 'Number of workers or operators assigned to this work center per shift. Used in labor capacity planning, workforce scheduling via Kronos, and standard cost calculations.. Valid values are `^[0-9]+$`',
    `number_of_machines` STRING COMMENT 'Count of individual machines or equipment units grouped within this work center. Used to calculate aggregate capacity and determine parallel processing capability.. Valid values are `^[0-9]+$`',
    `number_of_shifts` STRING COMMENT 'Number of production shifts per day scheduled at this work center. Directly determines available capacity hours and is used in shift-based scheduling and OEE calculations.. Valid values are `^[1-9][0-9]*$`',
    `oee_target_percent` DECIMAL(18,2) COMMENT 'Target Overall Equipment Effectiveness (OEE) percentage set for this work center, representing the desired level of availability, performance, and quality combined. Used as the KPI benchmark in TPM and continuous improvement programs.. Valid values are `^(100(.0{1,2})?|[0-9]{1,2}(.d{1,2})?)$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility where this work center is physically located. Supports multi-plant and multinational capacity planning.. Valid values are `^[A-Z0-9]{1,10}$`',
    `production_strategy` STRING COMMENT 'Manufacturing execution strategy applicable to this work center: Make-to-Order (MTO), Make-to-Stock (MTS), Engineer-to-Order (ETO), or Assemble-to-Order (ATO). Drives order type and scheduling behavior.. Valid values are `MTO|MTS|ETO|ATO`',
    `queue_time_hours` DECIMAL(18,2) COMMENT 'Standard waiting time in hours that a production order or WIP lot is expected to wait in queue before processing begins at this work center. Used in lead time scheduling and order float calculations.. Valid values are `^d{1,6}(.d{1,4})?$`',
    `responsible_supervisor` STRING COMMENT 'Name or employee identifier of the shop floor supervisor or foreman accountable for operations at this work center. Used for escalation routing, shift handover, and accountability reporting.',
    `routing_usage` STRING COMMENT 'Defines the permitted usage of this work center in routing operations: production routing, inspection routing, rework routing, maintenance routing, or all types. Controls which routing types can reference this work center.. Valid values are `production|inspection|rework|maintenance|all`',
    `setup_time_minutes` DECIMAL(18,2) COMMENT 'Standard time in minutes required to prepare (set up) the work center before production begins for a new operation or product. Used in routing time calculations and SMED improvement programs.. Valid values are `^d{1,6}(.d{1,4})?$`',
    `shift_duration_hours` DECIMAL(18,2) COMMENT 'Standard duration in hours of a single production shift at this work center. Combined with number_of_shifts to derive total daily available capacity.. Valid values are `^d{1,3}(.d{1,2})?$`',
    `standard_value_key` STRING COMMENT 'SAP PP standard value key defining which standard values (setup, machine, labor, teardown) are relevant for operations at this work center. Drives costing formula selection.. Valid values are `^[A-Z0-9]{1,10}$`',
    `status` STRING COMMENT 'Current operational status of the work center. Active work centers are available for scheduling; under_maintenance are temporarily unavailable; decommissioned are retired from production.. Valid values are `active|inactive|under_maintenance|decommissioned|planned`',
    `takt_time_seconds` DECIMAL(18,2) COMMENT 'The rate at which products must be completed at this work center to meet customer demand, expressed in seconds per unit. Calculated as available production time divided by customer demand rate. Core metric in Lean Manufacturing and line balancing.. Valid values are `^d{1,6}(.d{1,4})?$`',
    `teardown_time_minutes` DECIMAL(18,2) COMMENT 'Standard time in minutes required to clean up and restore the work center after production of an operation is complete. Included in total operation lead time calculations.. Valid values are `^d{1,6}(.d{1,4})?$`',
    `type` STRING COMMENT 'Classification of the work center by its primary operational mode: machine (CNC, robot), labor (manual assembly), process (chemical/batch), assembly (multi-component joining), inspection (QA station), or storage (buffer/WIP area).. Valid values are `machine|labor|process|assembly|inspection|storage`',
    `utilization_rate_percent` DECIMAL(18,2) COMMENT 'Percentage of available capacity time that is actually scheduled or consumed by production orders. A key input to capacity leveling and bottleneck analysis in MRP II.. Valid values are `^(100(.0{1,2})?|[0-9]{1,2}(.d{1,2})?)$`',
    `valid_from_date` DATE COMMENT 'Date from which this work center record is valid and available for production scheduling and routing assignments. Supports time-dependent master data management in SAP PP.. Valid values are `^d{4}-d{2}-d{2}$`',
    `valid_to_date` DATE COMMENT 'Date until which this work center record is valid. After this date, the work center is no longer available for new routing or scheduling assignments. Supports planned decommissioning and capacity transitions.. Valid values are `^d{4}-d{2}-d{2}$`',
    CONSTRAINT pk_work_center PRIMARY KEY(`work_center_id`)
) COMMENT 'Master data for manufacturing work centers (SAP PP Work Center / Opcenter Resource). Represents a physical or logical production unit on the shop floor — a machine, assembly cell, production line, or labor group. Stores work center code, description, plant, cost center linkage, capacity category, available capacity (shifts, hours), efficiency rate, utilization rate, setup time, teardown time, queue time, move time, work center type (machine, labor, process), and responsible supervisor. SSOT for work center capacity and routing assignments used in MRP II planning and shop floor scheduling.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`routing` (
    `routing_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying a manufacturing routing record in the Silver Layer lakehouse. Serves as the primary key for all routing-related joins and references.',
    `bop_id` BIGINT COMMENT 'Foreign key linking to engineering.bop. Business justification: Manufacturing routings implement engineering Bill of Process specifications. Production engineering translates design intent into executable shop floor operations with this link.',
    `base_quantity` DECIMAL(18,2) COMMENT 'Reference quantity for which all standard times (setup, machine, labor) in the routing operations are defined. Typically 1 or a standard batch size. Used to scale standard values proportionally for different production order quantities.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `base_unit_of_measure` STRING COMMENT 'Unit of measure corresponding to the base quantity (e.g., EA=Each, KG=Kilogram, L=Liter, M=Meter). Aligns with the SAP material master base unit and ISO unit standards.. Valid values are `^[A-Z]{2,3}$`',
    `bop_reference` STRING COMMENT 'Reference identifier linking this routing to the corresponding Bill of Process (BoP) in Siemens Teamcenter PLM. The BoP defines the engineering-side process structure, while the routing is the ERP execution counterpart.',
    `costing_relevance` BOOLEAN COMMENT 'Indicates whether this routing is used as the basis for standard cost calculation in SAP CO Product Costing. When true, the routings standard times and work center activity rates are used to compute the manufacturing cost component of the product standard cost.. Valid values are `true|false`',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country where manufacturing under this routing takes place. Used for regulatory compliance (CE Marking, RoHS, REACH), customs declarations, and multinational production reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the routing record was originally created in the source system (SAP PP). Used for audit trail, data lineage, and routing lifecycle tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `description` STRING COMMENT 'Detailed textual description of the routing, explaining the overall manufacturing process, intended product, and any special processing notes for production planners and shop floor engineers.',
    `ecn_number` STRING COMMENT 'Reference to the Engineering Change Notice (ECN) or Engineering Change Order (ECO) that authorized the creation or last modification of this routing. Provides traceability between process changes and engineering change management.. Valid values are `^[A-Z0-9_-]{1,20}$`',
    `group` STRING COMMENT 'SAP PP routing group key that, together with the routing group counter, uniquely identifies a task list. Groups related routing variants for the same material or product family.. Valid values are `^[A-Z0-9_-]{1,8}$`',
    `group_counter` STRING COMMENT 'SAP PP group counter that differentiates multiple routing variants (standard, rework, alternate) within the same routing group. Combined with routing_group to form the unique SAP task list key.. Valid values are `^[0-9]{1,2}$`',
    `has_alternative_sequences` BOOLEAN COMMENT 'Indicates whether the routing contains alternative operation sequences that can be selected based on work center availability, capacity constraints, or material characteristics. Supports flexible shop floor scheduling.. Valid values are `true|false`',
    `has_inspection_operations` BOOLEAN COMMENT 'Indicates whether the routing includes quality inspection operations (linked to SAP QM inspection characteristics). Supports integration with the Quality Management System (QMS) and First Article Inspection (FAI) processes.. Valid values are `true|false`',
    `has_parallel_sequences` BOOLEAN COMMENT 'Indicates whether the routing contains parallel operation sequences (concurrent process branches) in addition to the standard sequence. Parallel sequences enable simultaneous execution of independent operations, reducing total lead time.. Valid values are `true|false`',
    `language_code` STRING COMMENT 'ISO 639-1 two-letter language code for the language in which the routing description and operation texts are maintained (e.g., EN, DE, FR, ZH). Supports multilingual routing documentation for global manufacturing operations.. Valid values are `^[A-Z]{2}$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent modification to the routing record in the source system. Used for change detection, incremental data loading in the lakehouse Silver Layer, and audit compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `lot_size_from` DECIMAL(18,2) COMMENT 'Minimum production lot size for which this routing is valid. Used in SAP PP lot-size-dependent routing selection to ensure the correct process sequence is applied based on production quantity.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `lot_size_to` DECIMAL(18,2) COMMENT 'Maximum production lot size for which this routing is valid. Together with lot_size_from, defines the quantity range for routing selection during production order creation and MRP II planning.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `material_number` STRING COMMENT 'SAP material master number of the finished or semi-finished product that this routing is designed to manufacture. Links the routing to the product engineering domain and Bill of Materials (BOM).. Valid values are `^[A-Z0-9_-]{1,40}$`',
    `name` STRING COMMENT 'Short descriptive name or title of the routing, providing a human-readable label for the manufacturing process sequence (e.g., Standard Assembly Routing – Motor Drive Unit).',
    `number` STRING COMMENT 'Business-facing alphanumeric identifier for the routing as defined in SAP PP (Routing Group / Task List Number). Used by production planners and shop floor personnel to reference the manufacturing process sequence.. Valid values are `^[A-Z0-9_-]{1,20}$`',
    `operation_count` STRING COMMENT 'Total number of individual operations (process steps) defined in this routing. Provides a quick indicator of routing complexity and is used for routing comparison and process simplification analysis.. Valid values are `^[0-9]+$`',
    `plant_code` STRING COMMENT 'SAP organizational unit code identifying the manufacturing plant where this routing is valid and executed. Supports multi-plant, multinational operations and plant-level capacity planning.. Valid values are `^[A-Z0-9]{1,4}$`',
    `plm_routing_code` STRING COMMENT 'External identifier of the corresponding routing or process plan object in Siemens Teamcenter PLM. Enables bidirectional traceability between the ERP routing (SAP PP) and the PLM process definition for Engineering Change Management.',
    `production_strategy` STRING COMMENT 'Manufacturing production strategy associated with this routing: Make-to-Order (MTO), Make-to-Stock (MTS), Engineer-to-Order (ETO), or Assemble-to-Order (ATO). Determines how the routing is triggered and consumed in production order processing.. Valid values are `MTO|MTS|ETO|ATO`',
    `released_timestamp` TIMESTAMP COMMENT 'Date and time when the routing status was changed to released, indicating formal approval for production use. Key lifecycle event for quality management traceability and Engineering Change Order (ECO) implementation tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `revision_level` STRING COMMENT 'Alphanumeric revision level or version identifier of the routing (e.g., A, B, 01, 02). Incremented with each approved Engineering Change Order (ECO). Supports routing version control and audit traceability.. Valid values are `^[A-Z0-9]{1,3}$`',
    `scheduling_relevance` BOOLEAN COMMENT 'Indicates whether this routing is used for production order scheduling and capacity requirements planning (CRP) in MRP II. When true, the routing drives work center load calculations and finite/infinite scheduling.. Valid values are `true|false`',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which this routing record was sourced (e.g., SAP_S4HANA for PP module, TEAMCENTER for PLM BoP, OPCENTER for MES routing). Supports data lineage and multi-system reconciliation in the lakehouse.. Valid values are `SAP_S4HANA|TEAMCENTER|OPCENTER|LEGACY`',
    `status` STRING COMMENT 'Current lifecycle status of the routing record: draft during initial creation, released when approved for production use, frozen when locked against changes, obsolete when superseded, under_review during Engineering Change Order (ECO) processing.. Valid values are `draft|released|frozen|obsolete|under_review`',
    `takt_time_sec` DECIMAL(18,2) COMMENT 'Takt time in seconds for this routing, representing the rate at which products must be completed to meet customer demand. Calculated as available production time divided by customer demand rate. Key Lean Manufacturing metric for line balancing and flow design.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `task_list_type` STRING COMMENT 'SAP PP task list type code indicating the category of the routing: N=Standard Routing, R=Reference Operation Set, M=Rate Routing, S=Rough-Cut Planning Profile, E=Equipment Task List, Q=Inspection Plan. Drives system behavior in MRP II and shop floor scheduling.. Valid values are `N|R|M|S|E|Q`',
    `total_labor_time_min` DECIMAL(18,2) COMMENT 'Aggregate standard labor time in minutes across all routing operations for the base quantity. Used for workforce capacity planning, standard cost calculation (labor cost component), and productivity analysis.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `total_lead_time_days` DECIMAL(18,2) COMMENT 'Total manufacturing lead time in days for the complete routing, representing the elapsed calendar time from start of first operation to completion of last operation. Used in MRP II scheduling, ATP (Available to Promise), and delivery date calculation.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `total_machine_time_min` DECIMAL(18,2) COMMENT 'Aggregate standard machine processing time in minutes across all routing operations for the base quantity. Core input for MRP II capacity requirements planning (CRP), takt time analysis, and production scheduling.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `total_setup_time_min` DECIMAL(18,2) COMMENT 'Aggregate standard setup time in minutes across all operations in the routing for the base quantity. Used for capacity planning, costing, and OEE (Overall Equipment Effectiveness) analysis. Supports SMED (Single-Minute Exchange of Dies) improvement tracking.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `type` STRING COMMENT 'Classification of the routing variant indicating its intended use: standard for normal production, rework for non-conforming material reprocessing, alternate for secondary process paths, inspection for quality inspection routings, reference for reference operation sets.. Valid values are `standard|rework|alternate|inspection|reference`',
    `usage` STRING COMMENT 'SAP PP usage key defining the application context of the routing (e.g., 1=Production, 2=Engineering, 3=Universal, 5=Sales and Distribution). Controls which business processes can reference this routing.. Valid values are `^[0-9]{1,3}$`',
    `valid_from` DATE COMMENT 'Date from which this routing version is effective and valid for use in production order creation and MRP II planning. Supports date-effective routing management and Engineering Change Order (ECO) implementation scheduling.. Valid values are `^d{4}-d{2}-d{2}$`',
    `valid_to` DATE COMMENT 'Date until which this routing version remains valid for production use. After this date, the routing is superseded by a newer version or marked obsolete. Used for routing version lifecycle management.. Valid values are `^d{4}-d{2}-d{2}$`',
    CONSTRAINT pk_routing PRIMARY KEY(`routing_id`)
) COMMENT 'Master data for manufacturing routings (SAP PP Routing / BoP — Bill of Process). Defines the sequence of operations required to manufacture a product, including operation numbers, work center assignments, standard values (setup time, machine time, labor time), control keys, and inspection characteristics. Supports multiple routing variants (standard, rework, alternate). Links to the engineering BOM and drives MRP II capacity planning, shop floor scheduling, and costing. SSOT for the manufacturing process sequence and standard times.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`routing_operation` (
    `routing_operation_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying a single operation step within a manufacturing routing. Serves as the primary key for the routing_operation entity in the Silver Layer lakehouse.',
    `bop_operation_id` BIGINT COMMENT 'Foreign key linking to engineering.bop_operation. Business justification: Routing operations execute specific BOP operations defined by engineering. Work instructions and quality checkpoints reference this to ensure design compliance during manufacturing.',
    `routing_id` BIGINT COMMENT 'Foreign key linking to production.routing. Business justification: routing_operation is a child step within a routing. The FK routing_id creates the proper parent-child relationship between individual operation steps and their parent routing, enabling routing structu',
    `task_list_id` BIGINT COMMENT 'Foreign key linking to asset.task_list. Business justification: Routing operations for production equipment setup or changeover reference asset task lists that define the exact maintenance or inspection steps required. Process engineers link these to standardize o',
    `work_center_id` BIGINT COMMENT 'Foreign key linking to production.work_center. Business justification: routing_operation is assigned to a specific work_center for execution. The FK work_center_id normalizes the work_center_code reference and enables joins to work_center master data for routing analysis',
    `activity_type_code` STRING COMMENT 'SAP CO activity type code (e.g., MACH for machine hours, LABOR for labor hours) used to calculate the standard cost of this operation. Links operation time values to cost rates defined in the controlling module for product cost calculation.',
    `base_quantity` DECIMAL(18,2) COMMENT 'Reference quantity to which the standard time values apply. For example, if standard machine time is 5 minutes per 100 pieces, the base quantity is 100. Enables accurate time scaling for variable production lot sizes.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `change_number` STRING COMMENT 'Engineering Change Notice (ECN) or Engineering Change Order (ECO) number that authorized the creation or modification of this routing operation. Provides full traceability of routing changes back to the originating engineering change request.',
    `control_key` STRING COMMENT 'SAP routing control key that governs operation behavior — determines whether the operation is scheduled, costed, printed on shop floor papers, requires confirmation, or triggers quality inspection. Examples: PP01 (internal processing), PP03 (external processing), QM01 (inspection).',
    `cost_center_code` STRING COMMENT 'SAP Controlling (CO) cost center code associated with this operations work center. Enables operation-level cost rollup, activity-based costing, and COGS allocation to the correct organizational unit.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this routing operation record was first created in the system. Used for audit trail, data lineage tracking, and compliance with ISO 9001 record control requirements.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the external processing price (e.g., USD, EUR, GBP, JPY). Supports multi-currency operations in multinational manufacturing environments.. Valid values are `^[A-Z]{3}$`',
    `external_processing_price` DECIMAL(18,2) COMMENT 'Standard price agreed with the subcontractor for performing this operation externally. Used for purchase order creation, standard cost calculation, and make-vs-buy analysis. Applicable only when is_subcontracting is true.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `is_inspection_operation` BOOLEAN COMMENT 'Indicates whether this operation is a quality inspection step that triggers an inspection lot in the Quality Management (QM) module. When true, the operation creates an inspection point and requires quality results recording before the production order can be confirmed.. Valid values are `true|false`',
    `is_milestone_operation` BOOLEAN COMMENT 'Indicates whether this operation is a milestone (gate) in the production routing. Milestone operations must be confirmed before subsequent operations can begin, enabling stage-gate control of the production flow and partial goods receipt.. Valid values are `true|false`',
    `is_subcontracting` BOOLEAN COMMENT 'Indicates whether this operation is performed by an external subcontractor rather than internally. When true, the operation triggers a subcontracting purchase order in SAP MM and requires goods issue/receipt processing for the outsourced step.. Valid values are `true|false`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this routing operation record. Supports change tracking, audit compliance, and incremental data loading in the Databricks Silver Layer lakehouse pipeline.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `maximum_lot_size` DECIMAL(18,2) COMMENT 'Maximum production quantity that can be processed in a single run of this operation. Prevents overloading of work centers and ensures quality control limits are not exceeded per batch.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `minimum_lot_size` DECIMAL(18,2) COMMENT 'Minimum production quantity that can be processed in a single run of this operation. Constrains MRP II lot sizing and production order splitting decisions to ensure operational efficiency.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `move_time` DECIMAL(18,2) COMMENT 'Standard time required to transport materials or WIP from this operation to the next work center. Contributes to total lead time calculation and is used in scheduling to account for inter-operation material movement.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `number_of_labor_resources` STRING COMMENT 'Standard number of workers (labor resources) required to perform this operation simultaneously. Used in workforce capacity planning, labor cost calculation, and shop floor staffing models.. Valid values are `^[0-9]+$`',
    `number_of_machines` STRING COMMENT 'Standard number of machines required to perform this operation simultaneously. Used in machine capacity planning and OEE-based scheduling to determine resource requirements per production order.. Valid values are `^[0-9]+$`',
    `operation_long_text` STRING COMMENT 'Detailed work instructions, standard operating procedure (SOP) narrative, or technical guidance for performing the operation. Includes tooling requirements, safety precautions, quality checkpoints, and step-by-step execution notes.',
    `operation_number` STRING COMMENT 'Sequential numeric identifier for the operation within the routing, typically in increments of 10 (e.g., 0010, 0020, 0030). Determines the execution sequence on the shop floor and drives MES scheduling order.. Valid values are `^[0-9]{4}$`',
    `operation_short_text` STRING COMMENT 'Brief descriptive label for the operation step (e.g., CNC Milling, Spot Welding, Final Assembly, Visual Inspection, Powder Coating). Displayed on shop floor traveler documents and work order printouts.',
    `operation_type` STRING COMMENT 'Classification of the manufacturing operation by process type. Enables filtering and grouping of operations for capacity analysis, cost rollup by process category, and shop floor scheduling by operation family.. Valid values are `machining|welding|assembly|inspection|painting|heat_treatment|testing|packaging|cleaning|grinding|drilling|forming|casting|forging|coating|other`',
    `operation_unit` STRING COMMENT 'Unit of measure for the operation quantity (e.g., EA for each, KG for kilogram, M for meter). Defines how the operation output is counted and reported on the shop floor and in MES confirmations.. Valid values are `EA|KG|LB|M|M2|M3|L|PC|SET|HR|MIN`',
    `overlap_type` STRING COMMENT 'Defines whether and how this operation can overlap with the preceding operation in the routing sequence. no_overlap requires full completion before the next starts; time_overlap allows a fixed time offset; quantity_overlap allows partial quantity transfer. Enables lead time compression in scheduling.. Valid values are `no_overlap|time_overlap|quantity_overlap`',
    `overlap_value` DECIMAL(18,2) COMMENT 'Numeric value defining the extent of overlap with the preceding operation. Interpreted based on overlap_type: for time_overlap, the number of time units (per time_unit); for quantity_overlap, the minimum quantity to transfer before the next operation starts.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility where this routing operation is executed. Supports multi-plant routing management and plant-specific capacity planning in multinational operations.',
    `queue_time` DECIMAL(18,2) COMMENT 'Standard waiting time (queue) before this operation begins, representing the time a work order waits in the queue at the work center. Included in lead time calculation and critical path scheduling. Expressed in the unit defined by time_unit.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `scrap_percentage` DECIMAL(18,2) COMMENT 'Expected percentage of material or components that will be scrapped during this operation under normal production conditions. Used in MRP II to inflate planned order quantities, in standard cost calculation, and in yield analysis. Expressed as a percentage (0–100).. Valid values are `^(100(.0{1,2})?|[0-9]{1,2}(.[0-9]{1,2})?)$`',
    `standard_labor_time` DECIMAL(18,2) COMMENT 'Standard labor (person) time required per base quantity unit for this operation. Used for labor cost rollup, workforce capacity planning, and standard cost calculation. Expressed in the unit defined by time_unit.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `standard_machine_time` DECIMAL(18,2) COMMENT 'Standard machine processing time per base quantity unit for this operation. Drives machine capacity loading in MRP II, OEE calculations, and takt time analysis. Expressed in the unit defined by time_unit.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `standard_setup_time` DECIMAL(18,2) COMMENT 'Standard time required to set up the work center before production begins for this operation (e.g., tooling changeover, fixture installation, machine calibration). Used in capacity planning, SMED analysis, and production scheduling. Expressed in the unit defined by time_unit.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `standard_teardown_time` DECIMAL(18,2) COMMENT 'Standard time required to dismantle tooling, clean the work center, and restore it to a ready state after the operation completes. Included in total operation duration for scheduling and capacity loading.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `status` STRING COMMENT 'Current lifecycle status of the routing operation record. active operations are available for production order assignment; inactive are temporarily disabled; under_review are pending engineering change approval; obsolete are retired and no longer used.. Valid values are `active|inactive|under_review|obsolete`',
    `time_unit` STRING COMMENT 'Unit of measure applied to all standard time values (setup, machine, labor, teardown) for this operation. Ensures consistent interpretation of time fields across scheduling, costing, and capacity planning systems.. Valid values are `MIN|HR|SEC|DAY`',
    `valid_from_date` DATE COMMENT 'Date from which this routing operation version becomes effective and can be used in production order scheduling. Supports date-effective routing management and engineering change control (ECN/ECO) implementation.. Valid values are `^d{4}-d{2}-d{2}$`',
    `valid_to_date` DATE COMMENT 'Date after which this routing operation version expires and is no longer valid for new production orders. Used in conjunction with valid_from_date to manage engineering change effectivity and routing version control.. Valid values are `^d{4}-d{2}-d{2}$`',
    `wait_time` DECIMAL(18,2) COMMENT 'Standard time the material must wait after this operation completes before the next operation can begin (e.g., curing time, cooling time, drying time). Included in lead time scheduling and critical path analysis.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `work_center_code` STRING COMMENT 'Alphanumeric code identifying the work center (machine, production cell, or labor group) where this operation is performed. Used for capacity planning, scheduling, and cost center assignment in MRP II resource planning.',
    CONSTRAINT pk_routing_operation PRIMARY KEY(`routing_operation_id`)
) COMMENT 'Individual operation steps within a manufacturing routing. Each record represents a single operation in the production sequence — e.g., machining, welding, assembly, inspection, painting. Stores operation number, operation short text, work center, control key, standard setup time, standard machine time, standard labor time, operation unit, scrap percentage, inspection flag, and long-text instructions. Enables granular shop floor scheduling, capacity loading per operation, and operation-level cost rollup. Child entity of routing.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`schedule` (
    `schedule_id` BIGINT COMMENT 'Unique surrogate identifier for each production schedule record in the Databricks Silver Layer. Serves as the primary key for the production_schedule data product.',
    `batch_id` BIGINT COMMENT 'Foreign key linking to production.batch. Business justification: production_schedule references a batch for batch-managed production planning. The FK batch_id normalizes the batch_number string reference and enables joins to batch master data for batch-level schedu',
    `forecast_id` BIGINT COMMENT 'Foreign key linking to sales.sales_forecast. Business justification: Master production scheduling uses sales forecasts to plan capacity and material requirements for make-to-stock items. Production planners align manufacturing schedules with anticipated demand from sal',
    `fulfillment_plan_id` BIGINT COMMENT 'Foreign key linking to order.fulfillment_plan. Business justification: Production schedules are built to satisfy fulfillment plans that aggregate customer order commitments. Master schedulers align production schedules directly to fulfillment plans to ensure on-time deli',
    `planned_order_id` BIGINT COMMENT 'Foreign key linking to production.planned_order. Business justification: production_schedule is built from MRP-generated planned_orders. The FK planned_order_id normalizes the planned_order_number string reference and enables joins to planned_order master data for schedule',
    `routing_id` BIGINT COMMENT 'Foreign key linking to production.routing. Business justification: production_schedule references a routing for scheduling purposes. The FK routing_id normalizes the routing_number string reference and enables joins to routing master data for capacity planning and sc',
    `shift_id` BIGINT COMMENT 'Foreign key linking to production.shift. Business justification: Production schedules specify which shift executes the work. Shift supervisors use this for crew assignments and labor planning.',
    `work_center_id` BIGINT COMMENT 'Foreign key linking to production.work_center. Business justification: production_schedule is planned for a specific work_center. The FK work_center_id normalizes the work_center_code reference and enables joins to work_center master data for capacity load analysis and s',
    `atp_relevant` BOOLEAN COMMENT 'Indicates whether this production schedule entry contributes to Available to Promise (ATP) stock calculations in SAP S/4HANA SD. When true, the planned production quantity is included in ATP/CTP commitment logic for the order domain.. Valid values are `true|false`',
    `batch_number` STRING COMMENT 'Batch or lot number assigned to the production run under this schedule entry, used for batch traceability in regulated or quality-controlled manufacturing environments. Aligns with SAP batch management and QM module requirements.',
    `capacity_load_percent` DECIMAL(18,2) COMMENT 'Percentage of the work centers available capacity consumed by this production schedule entry. A value of 100 indicates full utilization; values above 100 indicate overload conditions requiring rescheduling or capacity leveling in SAP PP.. Valid values are `^(100(.00?)?|[0-9]{1,2}(.[0-9]{1,2})?)$`',
    `confirmed_quantity` DECIMAL(18,2) COMMENT 'Quantity confirmed as feasible by capacity planning and resource availability checks in SAP PP or Siemens Opcenter MES. May differ from planned quantity when capacity constraints exist. Used for Capable to Promise (CTP) commitments.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the manufacturing plant location where this production schedule is executed. Supports multinational reporting, regulatory compliance tracking (CE, RoHS, REACH), and regional capacity analysis.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this production schedule record was first created in the source system (SAP S/4HANA PP or Siemens Opcenter MES). Used for data lineage, audit trail, and Silver Layer ingestion tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}[+-]d{2}:d{2}$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the plants local currency, used when cost estimates or standard cost values are associated with this production schedule entry in SAP CO.. Valid values are `^[A-Z]{3}$`',
    `cycle_time_seconds` DECIMAL(18,2) COMMENT 'Planned cycle time in seconds for producing one unit at the assigned work center under this schedule. Used to validate feasibility against takt time targets and to calculate total scheduled duration for capacity planning.. Valid values are `^[0-9]+(.[0-9]{1,2})?$`',
    `freeze_horizon_date` DATE COMMENT 'Date up to which the production schedule is frozen and protected from automatic MRP II rescheduling. Orders within the freeze horizon require manual authorization to change, ensuring shop floor stability and preventing nervousness in the plan.. Valid values are `^d{4}-d{2}-d{2}$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent update to this production schedule record in the source system. Used for change detection in the Databricks Silver Layer incremental load process and audit compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}[+-]d{2}:d{2}$`',
    `material_description` STRING COMMENT 'Short description of the material or finished good to be produced, as maintained in the SAP material master. Provides human-readable context for schedule review and shop floor communication.',
    `material_number` STRING COMMENT 'SAP S/4HANA material master number identifying the finished good or semi-finished material to be produced under this schedule. Used to link to BOM, routing, and MRP planning data.',
    `mrp_controller` STRING COMMENT 'SAP MRP controller code or name responsible for managing the materials planning parameters and reviewing the generated production schedule. Used for accountability and exception management in the planning process.',
    `mrp_run_date` DATE COMMENT 'Date on which the MRP II planning run was executed in SAP S/4HANA that generated or last updated this production schedule. Provides auditability of the planning cycle and enables comparison between planning runs.. Valid values are `^d{4}-d{2}-d{2}$`',
    `name` STRING COMMENT 'Descriptive human-readable name for the production schedule, used for identification in planning dashboards and MES scheduling boards (e.g., Week 32 Motor Assembly Plan - Plant DE01).',
    `number` STRING COMMENT 'Business-facing alphanumeric identifier for the production schedule, used for cross-system referencing between SAP S/4HANA PP and Siemens Opcenter MES. Typically follows a plant-year-sequence format.. Valid values are `^PS-[0-9]{4}-[0-9]{6}$`',
    `oee_target_percent` DECIMAL(18,2) COMMENT 'Target Overall Equipment Effectiveness (OEE) percentage set for the work center during this schedule period. OEE combines availability, performance, and quality rates. Used as a KPI baseline for shop floor performance monitoring via Siemens MindSphere and Opcenter Analytics.. Valid values are `^(100(.00?)?|[0-9]{1,2}(.[0-9]{1,2})?)$`',
    `planned_cost` DECIMAL(18,2) COMMENT 'Estimated total production cost for this schedule entry in the plants local currency, derived from SAP CO standard cost estimates. Includes material, labor, and overhead components. Used for budget planning and COGS analysis.. Valid values are `^[0-9]+(.[0-9]{1,2})?$`',
    `planned_order_number` STRING COMMENT 'Reference to the MRP-generated planned order in SAP S/4HANA PP that this schedule entry is derived from. Enables traceability from the production schedule back to the originating MRP II planning run and demand signal.',
    `planned_quantity` DECIMAL(18,2) COMMENT 'Total quantity of the material planned for production within this schedule entrys time bucket and work center. Expressed in the materials base unit of measure as defined in the SAP material master.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `planning_horizon_end` DATE COMMENT 'The last calendar date of the planning horizon covered by this production schedule. Defines the end boundary for MRP II capacity planning and scheduled production orders.. Valid values are `^d{4}-d{2}-d{2}$`',
    `planning_horizon_start` DATE COMMENT 'The first calendar date of the planning horizon covered by this production schedule. Defines the start boundary for MRP II capacity planning and scheduled production orders.. Valid values are `^d{4}-d{2}-d{2}$`',
    `plant_code` STRING COMMENT 'SAP S/4HANA plant identifier representing the manufacturing facility for which this production schedule is generated. Aligns with the organizational unit in SAP PP and Siemens Opcenter MES plant configuration.. Valid values are `^[A-Z0-9]{4}$`',
    `priority` STRING COMMENT 'Numeric priority ranking assigned to this production schedule entry for shop floor sequencing. Lower values indicate higher priority. Used by Siemens Opcenter MES to sequence competing orders at shared work centers.. Valid values are `^[1-9][0-9]*$`',
    `production_strategy` STRING COMMENT 'Manufacturing execution strategy governing how production orders are triggered. Make to Order (MTO) produces against customer orders; Make to Stock (MTS) produces to replenish inventory; Engineer to Order (ETO) requires custom engineering; Assemble to Order (ATO) assembles from standard components on demand.. Valid values are `MTO|MTS|ETO|ATO`',
    `released_timestamp` TIMESTAMP COMMENT 'Date and time when the production schedule status was changed to released, authorizing shop floor execution. Captured for audit trail and compliance with ISO 9001 documented information requirements.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}[+-]d{2}:d{2}$`',
    `routing_number` STRING COMMENT 'Reference to the SAP PP routing (Bill of Process) that defines the sequence of operations, work centers, and standard times for producing the scheduled material. Ensures the schedule is aligned with the approved manufacturing process.',
    `scheduled_end_date` DATE COMMENT 'Planned calendar date on which production for this schedule entry is expected to be completed at the assigned work center. Drives delivery date commitments and ATP/CTP calculations for the order domain.. Valid values are `^d{4}-d{2}-d{2}$`',
    `scheduled_end_time` TIMESTAMP COMMENT 'Precise date and time at which production is scheduled to complete, including shift and time-zone context. Used by Siemens Opcenter MES for detailed shop floor sequencing and completion tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}[+-]d{2}:d{2}$`',
    `scheduled_start_date` DATE COMMENT 'Planned calendar date on which production for this schedule entry is expected to begin at the assigned work center. Used for shop floor sequencing and ATP/CTP date commitments to the order domain.. Valid values are `^d{4}-d{2}-d{2}$`',
    `scheduled_start_time` TIMESTAMP COMMENT 'Precise date and time at which production is scheduled to begin, including shift and time-zone context. Used by Siemens Opcenter MES for detailed shop floor sequencing and takt time alignment.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}[+-]d{2}:d{2}$`',
    `scheduling_strategy` STRING COMMENT 'Scheduling direction applied during MRP II planning. Forward scheduling calculates the earliest possible completion date from a start date; backward scheduling calculates the latest start date from a required delivery date; mixed applies both depending on order priority.. Valid values are `forward|backward|mixed`',
    `shift_pattern` STRING COMMENT 'Shift configuration planned for this production schedule entry, defining the number of operating shifts per day. Drives available capacity calculation and Kronos Workforce Central labor scheduling alignment.. Valid values are `single_shift|double_shift|triple_shift|continuous`',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which this production schedule record originated. Supports data lineage tracking and conflict resolution when multiple systems contribute schedule data to the Silver Layer.. Valid values are `SAP_S4HANA|OPCENTER_MES|MANUAL`',
    `status` STRING COMMENT 'Current lifecycle status of the production schedule. Draft indicates initial planning; released means approved for shop floor execution; frozen means locked against changes; in_execution means active on the shop floor; completed means all planned orders fulfilled; cancelled means schedule voided.. Valid values are `draft|released|frozen|in_execution|completed|cancelled`',
    `takt_time_seconds` DECIMAL(18,2) COMMENT 'Target takt time in seconds for this production schedule entry, representing the rate at which products must be completed to meet customer demand. Calculated as available production time divided by customer demand rate. Used for line balancing and OEE target setting.. Valid values are `^[0-9]+(.[0-9]{1,2})?$`',
    `time_bucket` STRING COMMENT 'Granularity of the planning time bucket used in this schedule. Daily buckets are used for short-horizon detailed scheduling; weekly for medium-term MRP II planning; monthly for long-range capacity planning.. Valid values are `daily|weekly|monthly`',
    `unit_of_measure` STRING COMMENT 'Base unit of measure for the planned production quantity, aligned with the SAP material master UoM definition (e.g., EA for each, KG for kilogram, PC for piece). Ensures consistent quantity interpretation across MES and ERP systems.. Valid values are `EA|KG|LB|M|M2|M3|L|PC|SET|HR|MIN`',
    `version_number` STRING COMMENT 'Incremental version counter for the production schedule. Each re-planning or revision cycle increments this value, enabling version history tracking and comparison of planning iterations under MRP II.. Valid values are `^[0-9]+$`',
    `work_center_code` STRING COMMENT 'Identifier of the work center (machine group, production line, or cell) to which this schedule entry is assigned. Corresponds to the SAP PP work center and Siemens Opcenter MES resource definition used for capacity load calculation.',
    CONSTRAINT pk_schedule PRIMARY KEY(`schedule_id`)
) COMMENT 'Planned production schedule generated by MRP II / capacity planning for a planning horizon. Captures planned production quantities per finished good or semi-finished material, per work center, per time bucket (daily/weekly). Stores schedule version, planning horizon start/end, planned order references, capacity load percentage, scheduling strategy (forward/backward), takt time targets, and schedule status (draft, released, frozen). Drives shop floor execution sequencing and feeds ATP/CTP commitments to the order domain. SSOT for the production plan.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`planned_order` (
    `planned_order_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying a planned order record in the Databricks Silver Layer. Serves as the primary key for this entity.',
    `demand_forecast_id` BIGINT COMMENT 'Foreign key linking to procurement.demand_forecast. Business justification: Planned production orders are often driven by demand forecasts in make-to-stock manufacturing. Production planning teams trace planned orders back to the originating forecast to validate production qu',
    `forecast_id` BIGINT COMMENT 'Foreign key linking to sales.forecast. Business justification: Production planning teams consume sales forecasts to generate planned orders. MRP/demand-driven planning directly links a planned order back to the sales forecast that triggered it — used daily in pro',
    `fulfillment_plan_id` BIGINT COMMENT 'Foreign key linking to order.fulfillment_plan. Business justification: Planned production orders are created in direct response to a fulfillment plan. Production planning teams link planned orders to fulfillment plans daily to ensure manufacturing output aligns with comm',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: In batch-managed manufacturing, planned orders are pre-assigned a lot/batch number before production starts. This enables early reservation and traceability linkage between planning and inventory lot ',
    `mrp_planned_order_id` BIGINT COMMENT 'Foreign key linking to procurement.mrp_planned_order. Business justification: MRP generates planned orders that convert to production orders or purchase requisitions. Production planning uses MRP output daily to determine what to manufacture versus procure externally.',
    `order_type_id` BIGINT COMMENT 'Foreign key linking to production.order_type. Business justification: planned_order.order_type (STRING) is a denormalized reference to the order_type master. Adding order_type_id FK normalizes this relationship, enabling joins to retrieve order category, confirmation co',
    `priority_id` BIGINT COMMENT 'Foreign key linking to order.priority. Business justification: Planned orders inherit or align with customer order priority classifications. Production schedulers use order priority to sequence planned orders, ensuring high-priority customer orders drive manufact',
    `product_cost_estimate_id` BIGINT COMMENT 'Foreign key linking to finance.product_cost_estimate. Business justification: Planned orders reference the product cost estimate to determine standard costs for materials and activities. Production planning and cost controlling use this link to compare planned vs. actual costs ',
    `product_variant_id` BIGINT COMMENT 'Foreign key linking to engineering.product_variant. Business justification: Planned orders are created for a specific product variant. Production planning must reference the exact engineering variant to pull the correct BOM and routing. Used daily in MRP/ERP order generation.',
    `routing_id` BIGINT COMMENT 'Foreign key linking to production.routing. Business justification: planned_order references a routing for MRP planning purposes. The FK routing_id normalizes the routing_number string reference and enables joins to routing master data for lead time calculation and ca',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Planned orders specify the target storage location where produced goods will be received. MRP/MPS planning uses this to allocate storage capacity and direct goods receipt postings to the correct locat',
    `version_id` BIGINT COMMENT 'Foreign key linking to production.production_version. Business justification: planned_order references a production_version that defines the valid BOM and routing combination for manufacturing. The FK production_version_id normalizes the production_version string code and enabl',
    `work_center_id` BIGINT COMMENT 'Foreign key linking to production.work_center. Business justification: planned_order is assigned to a specific work_center for execution. The FK work_center_id normalizes the work_center_code reference and enables joins to work_center master data for MRP capacity plannin',
    `bom_number` STRING COMMENT 'Identifier of the Bill of Materials assigned to this planned order, defining the component materials and quantities required for production. Sourced from the production version or material master.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `conversion_timestamp` TIMESTAMP COMMENT 'The date and time at which the planned order was converted to a production order or purchase requisition. Supports lead time analysis and planning cycle performance measurement.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}[+-]d{2}:d{2}$`',
    `converted_order_number` STRING COMMENT 'The production order number or purchase requisition number generated when this planned order was converted. Provides traceability from planned demand to shop floor execution.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant where this planned order is to be executed. Supports multi-country regulatory compliance, reporting, and regional production analytics.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which the planned order record was created in the source system (SAP PP). Supports audit trail, data lineage, and planning cycle analysis.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}[+-]d{2}:d{2}$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the planned order cost valuation (e.g., USD, EUR, CNY). Supports multi-currency cost planning in multinational manufacturing operations.. Valid values are `^[A-Z]{3}$`',
    `demand_source_number` STRING COMMENT 'The identifier of the originating demand element (e.g., sales order number, forecast record ID, project WBS element) that triggered this planned order. Enables end-to-end demand-to-production traceability.',
    `demand_source_type` STRING COMMENT 'Classification of the originating demand element that triggered the creation of this planned order by MRP. Supports demand traceability and planning analysis across MTO, MTS, and ETO strategies.. Valid values are `sales_order|forecast|dependent_demand|safety_stock|manual|project`',
    `exception_message_code` STRING COMMENT 'SAP MRP exception message code indicating a planning anomaly requiring planner attention (e.g., 01=Reschedule in, 02=Reschedule out, 10=Cancel, 15=New planned order). Drives the MRP exception monitor workflow.. Valid values are `^[0-9]{2}$`',
    `goods_receipt_processing_days` DECIMAL(18,2) COMMENT 'The number of working days required to process the goods receipt after production completion before the material is available in stock. Included in MRP scheduling calculations.. Valid values are `^d+(.d{1,2})?$`',
    `in_house_production_days` DECIMAL(18,2) COMMENT 'The planned in-house production lead time in calendar days for this planned order, as determined by the routing or material master. Used by MRP for backward and forward scheduling calculations.. Valid values are `^d+(.d{1,2})?$`',
    `is_converted` BOOLEAN COMMENT 'Boolean flag indicating whether this planned order has been fully converted to a production order or purchase requisition. Once converted, the planned order is no longer an open planning element.. Valid values are `true|false`',
    `is_firmed` BOOLEAN COMMENT 'Boolean flag indicating whether the planned order has been manually firmed (fixed) by a planner, protecting it from automatic rescheduling or deletion by subsequent MRP runs. A firmed planned order represents a committed production plan.. Valid values are `true|false`',
    `last_changed_timestamp` TIMESTAMP COMMENT 'The date and time at which the planned order record was last modified in the source system. Supports change tracking, delta processing in the lakehouse pipeline, and audit compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}[+-]d{2}:d{2}$`',
    `lot_size_procedure` STRING COMMENT 'MRP lot-sizing procedure code used to calculate the planned order quantity (e.g., EX=Exact lot size, FX=Fixed lot size, HB=Replenishment up to maximum stock level, MB=Monthly lot size). Determines how demand quantities are grouped into planned orders.. Valid values are `EX|FX|HB|MB|PK|TB|WB|ZB`',
    `material_description` STRING COMMENT 'Short descriptive text for the material to be produced, sourced from the SAP material master. Supports readability in reports and dashboards without requiring a join to the material master.',
    `material_number` STRING COMMENT 'SAP material master identifier for the finished good or semi-finished product to be produced under this planned order. Links to the material master record in SAP MM.. Valid values are `^[A-Z0-9-]{1,40}$`',
    `mrp_controller` STRING COMMENT 'Three-character code identifying the MRP controller (planner) responsible for managing this planned order. Used for workload distribution and exception message routing in SAP PP.. Valid values are `^[A-Z0-9]{1,3}$`',
    `mrp_run_date` DATE COMMENT 'The calendar date on which the MRP or MPS run was executed that generated this planned order. Enables traceability of planned orders back to specific planning cycles.. Valid values are `^d{4}-d{2}-d{2}$`',
    `mrp_run_reference` STRING COMMENT 'Unique reference identifier for the MRP/MPS planning run that generated this planned order. Supports audit traceability and re-planning analysis.',
    `number` STRING COMMENT 'Business-facing alphanumeric identifier for the planned order as assigned by the MRP/MPS run in SAP PP. Used by planners and shop floor personnel to reference a specific planned production requirement.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `opening_date` DATE COMMENT 'The date on which the planned order should be converted to a production order or purchase requisition to allow sufficient lead time for execution. Calculated by MRP based on in-house production time and goods receipt processing time.. Valid values are `^d{4}-d{2}-d{2}$`',
    `planned_cost` DECIMAL(18,2) COMMENT 'Estimated total production cost for this planned order in the local plant currency, including material costs, labor costs, and overhead. Used for cost planning, variance analysis, and COGS forecasting.. Valid values are `^d+(.d{1,2})?$`',
    `planning_plant` STRING COMMENT 'The SAP plant code of the planning plant responsible for MRP planning of this material, which may differ from the production plant in cross-plant planning scenarios. Supports multi-plant and central planning configurations.. Valid values are `^[A-Z0-9]{4}$`',
    `plant_code` STRING COMMENT 'Four-character SAP plant identifier representing the manufacturing facility where the planned order is to be executed. Supports multi-plant production planning in a multinational environment.. Valid values are `^[A-Z0-9]{4}$`',
    `production_strategy` STRING COMMENT 'Manufacturing strategy governing how the planned order was generated: Make to Order (MTO), Make to Stock (MTS), Engineer to Order (ETO), or Assemble to Order (ATO). Determines demand traceability and inventory posting behavior.. Valid values are `MTO|MTS|ETO|ATO`',
    `requirements_date` DATE COMMENT 'The date by which the planned order quantity must be available to satisfy the originating demand requirement (e.g., sales order, dependent demand from a higher-level BOM). Aligns with the MRP requirements element date.. Valid values are `^d{4}-d{2}-d{2}$`',
    `routing_number` STRING COMMENT 'Identifier of the production routing (sequence of operations) assigned to this planned order. Defines the manufacturing process steps, work centers, and standard times for producing the material.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `scheduled_finish_date` DATE COMMENT 'The planned calendar date on which production of this order is scheduled to be completed, as calculated by MRP forward scheduling. Drives delivery date commitments and ATP checks.. Valid values are `^d{4}-d{2}-d{2}$`',
    `scheduled_start_date` DATE COMMENT 'The planned calendar date on which production of this order is scheduled to begin, as calculated by MRP backward scheduling. Used for capacity planning and material availability checks.. Valid values are `^d{4}-d{2}-d{2}$`',
    `scrap_percentage` DECIMAL(18,2) COMMENT 'Assembly scrap percentage applied to the planned order quantity to account for expected production losses. The planned quantity is inflated by this percentage to ensure the net required quantity is met after scrap.. Valid values are `^d{1,3}(.d{1,2})?$`',
    `special_procurement_type` STRING COMMENT 'SAP special procurement type key indicating non-standard procurement scenarios such as subcontracting, consignment, stock transfer, or phantom assembly. Influences how MRP generates and processes the planned order.. Valid values are `^[0-9]{2}$`',
    `status` STRING COMMENT 'Current lifecycle status of the planned order. created indicates MRP-generated and open; firmed indicates manually fixed and protected from MRP rescheduling; converted indicates fully converted to a production order or purchase requisition; partially_converted indicates a split conversion; deleted indicates cancelled.. Valid values are `created|firmed|converted|deleted|partially_converted`',
    `storage_location` STRING COMMENT 'SAP storage location code where the finished goods produced under this planned order will be received into inventory upon completion. Supports warehouse and inventory management integration.. Valid values are `^[A-Z0-9]{4}$`',
    `unit_of_measure` STRING COMMENT 'Base unit of measure for the planned quantity (e.g., EA for each, KG for kilogram, PC for piece, L for liter). Aligned with the material master base UoM in SAP MM.. Valid values are `^[A-Z]{2,5}$`',
    `work_center_code` STRING COMMENT 'Identifier of the primary work center or production resource assigned to execute this planned order. Used for capacity requirements planning (CRP) and shop floor scheduling.. Valid values are `^[A-Z0-9-]{1,8}$`',
    CONSTRAINT pk_planned_order PRIMARY KEY(`planned_order_id`)
) COMMENT 'MRP/MPS-generated planned order representing a future production requirement before conversion to a production order (SAP PP Planned Order). Stores planned order number, material number, plant, planned quantity, scheduled start date, scheduled finish date, order type (planned order for in-house production vs. purchase requisition), MRP run reference, firming indicator, and conversion status. Acts as the bridge between demand planning and shop floor execution. Converted to production orders upon release.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`shop_order_operation` (
    `shop_order_operation_id` BIGINT COMMENT 'Unique surrogate identifier for each shop order operation execution record in the silver layer lakehouse. Serves as the primary key for this entity.',
    `batch_id` BIGINT COMMENT 'Foreign key linking to production.batch. Business justification: shop_order_operation processes a specific batch on the shop floor. The FK batch_id normalizes the batch_number string reference and enables joins to batch master data for batch-level operation traceab',
    `machine_work_center_id` BIGINT COMMENT 'Identifier of the specific machine or equipment asset assigned to execute this operation. Links to the equipment master in Maximo EAM and Siemens MindSphere for OEE tracking, predictive maintenance, and asset utilization reporting.. Valid values are `^[A-Z0-9_-]{1,30}$`',
    `production_order_cost_id` BIGINT COMMENT 'Foreign key linking to finance.production_order_cost. Business justification: Each shop order operation incurs costs tracked in production_order_cost. Cost controllers link operational execution to financial cost objects daily to capture actual labor, machine, and overhead cost',
    `routing_id` BIGINT COMMENT 'Foreign key linking to production.routing. Business justification: shop_order_operation executes operations defined in a routing. The FK routing_id normalizes the routing_number string reference and enables joins to routing master data for operation sequence validati',
    `routing_operation_id` BIGINT COMMENT 'Foreign key linking to production.routing_operation. Business justification: shop_order_operation executes a specific routing_operation step on the shop floor. The FK routing_operation_id creates a direct relational link between execution records and their corresponding routin',
    `shift_id` BIGINT COMMENT 'Foreign key linking to production.shift. Business justification: shop_order_operation is executed during a specific shift. The FK shift_id normalizes the shift_code reference and enables joins to shift master data for shift-level productivity analysis, labor cost a',
    `tooling_equipment_id` BIGINT COMMENT 'Foreign key linking to engineering.tooling_equipment. Business justification: Shop order operations specify which engineering-defined tooling or equipment must be used. Process engineers define tooling requirements; production dispatchers assign them to operations. Critical for',
    `wip_stock_id` BIGINT COMMENT 'Foreign key linking to inventory.wip_stock. Business justification: Each shop order operation consumes or produces WIP inventory at intermediate routing steps. Production control links operations to WIP stock records to track in-process material quantities across the ',
    `work_center_id` BIGINT COMMENT 'Foreign key linking to production.work_center. Business justification: shop_order_operation executes at a specific work_center. The FK work_center_id normalizes the work_center_code reference and enables joins to work_center master data for capacity analysis, OEE attribu',
    `work_order_operation_id` BIGINT COMMENT 'Foreign key linking to asset.work_order_operation. Business justification: Production operations on a shop order sometimes require a concurrent maintenance work order operation (e.g., tooling change, calibration mid-run). Planners link these to coordinate production and main',
    `actual_finish_timestamp` TIMESTAMP COMMENT 'Actual date and time when the operation execution was completed on the shop floor, as recorded by the MES or operator confirmation. Used for cycle time calculation, throughput analysis, and OEE performance measurement.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `actual_labor_time_min` DECIMAL(18,2) COMMENT 'Actual direct labor time in minutes consumed by the operator(s) for this operation. Used for actual cost confirmation in SAP CO, labor efficiency variance analysis, and workforce productivity reporting.. Valid values are `^d{1,7}(.d{1,3})?$`',
    `actual_run_time_min` DECIMAL(18,2) COMMENT 'Actual machine or process run time in minutes for this operation, excluding setup and teardown. Core input for OEE performance rate calculation and cycle time variance analysis against standard run time.. Valid values are `^d{1,7}(.d{1,3})?$`',
    `actual_setup_time_min` DECIMAL(18,2) COMMENT 'Actual time in minutes spent on machine/tooling setup before production run began. Used for SMED (Single-Minute Exchange of Dies) analysis, changeover optimization, and OEE availability loss calculation.. Valid values are `^d{1,7}(.d{1,3})?$`',
    `actual_start_timestamp` TIMESTAMP COMMENT 'Actual date and time when the operation execution began on the shop floor, as recorded by the MES or operator confirmation. Used for cycle time calculation, schedule adherence, and OEE availability analysis.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `batch_number` STRING COMMENT 'Production batch or lot number associated with the material being processed in this operation. Critical for batch traceability, genealogy tracking, and regulatory compliance in industries requiring lot-level control (e.g., serialized components).. Valid values are `^[A-Z0-9-]{1,30}$`',
    `confirmation_number` STRING COMMENT 'SAP PP operation confirmation document number (CO11N confirmation number) generated when the operation is confirmed in the ERP system. Provides the audit trail link between the MES execution record and the ERP financial posting.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `control_key` STRING COMMENT 'SAP PP routing control key that governs the scheduling, confirmation, and costing behavior of this operation (e.g., PP01 for internally processed, PP03 for milestone confirmation). Determines whether the operation is relevant for scheduling, capacity planning, and cost confirmation.. Valid values are `^[A-Z0-9]{1,10}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this shop order operation record was first created in the source system (MES or ERP). Used for data lineage, audit trail, and silver layer ingestion tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `cycle_time_sec` DECIMAL(18,2) COMMENT 'Actual cycle time in seconds measured for this operation execution, calculated from actual start to actual finish divided by yield quantity. Compared against takt time and standard cycle time for OEE performance rate and lean analysis.. Valid values are `^d{1,7}(.d{1,3})?$`',
    `downtime_min` DECIMAL(18,2) COMMENT 'Total unplanned downtime in minutes recorded during this operation execution (e.g., machine breakdown, material shortage, quality stop). Core input for OEE availability rate calculation and downtime root cause analysis.. Valid values are `^d{1,7}(.d{1,3})?$`',
    `downtime_reason_code` STRING COMMENT 'Coded classification of the primary downtime cause during this operation (e.g., MECH_FAILURE, TOOLING, MATERIAL, QUALITY_HOLD, CHANGEOVER, PLANNED_MAINT). Used for Pareto analysis of downtime losses and TPM (Total Productive Maintenance) improvement programs.. Valid values are `^[A-Z0-9_]{1,20}$`',
    `hold_reason_code` STRING COMMENT 'Coded reason for placing this operation in held status (e.g., QUALITY_HOLD, MATERIAL_SHORTAGE, SAFETY_STOP, ENGINEERING_REVIEW). Populated when status is held. Supports root cause analysis and downtime categorization.. Valid values are `^[A-Z0-9_]{1,20}$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this shop order operation record in the source system. Used for incremental data loading, change detection, and audit trail in the Databricks silver layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `material_number` STRING COMMENT 'SAP material number of the finished or semi-finished product being produced by this operation. Enables product-level OEE, yield, and scrap analysis across production orders.. Valid values are `^[A-Z0-9-]{1,40}$`',
    `nc_flag` BOOLEAN COMMENT 'Indicates whether a non-conformance (NC) was detected during this operation. When true, triggers NCR (Non-Conformance Report) creation in the QMS and may initiate a hold on the production order. Key quality gate indicator.. Valid values are `true|false`',
    `nc_reference_number` STRING COMMENT 'Reference number of the Non-Conformance Report (NCR) raised against this operation when nc_flag is true. Provides direct traceability to the quality management system record for CAPA and disposition tracking.. Valid values are `^[A-Z0-9-]{1,30}$`',
    `operation_description` STRING COMMENT 'Human-readable description of the manufacturing operation being performed (e.g., CNC Milling, Weld Assembly, Final Inspection). Sourced from the routing master in SAP PP or Opcenter MES operation definition.',
    `operation_number` STRING COMMENT 'Sequential operation number within the production routing (e.g., 0010, 0020, 0030). Corresponds to the routing operation sequence in SAP PP and Opcenter MES, defining the order of execution steps within a production order.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `operation_type` STRING COMMENT 'Classification of the operation by its functional role in the manufacturing process. Distinguishes between value-adding processing steps, setup/teardown activities, quality inspection, rework, transport, and wait states for OEE and lean analysis.. Valid values are `setup|processing|teardown|inspection|rework|transport|wait`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility where this operation is executed. Supports multi-plant, multinational production reporting and cost allocation by plant.. Valid values are `^[A-Z0-9]{1,10}$`',
    `production_order_number` STRING COMMENT 'Business-visible production order number (SAP PP order number or Opcenter MES work order number) to which this operation belongs. Provides the primary traceability link between the operation execution record and the parent production order.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `production_strategy` STRING COMMENT 'Manufacturing strategy under which this operation is executed: Make-to-Order (MTO), Make-to-Stock (MTS), Engineer-to-Order (ETO), or Assemble-to-Order (ATO). Drives scheduling priority, cost allocation, and customer order linkage rules.. Valid values are `MTO|MTS|ETO|ATO`',
    `quantity_unit_of_measure` STRING COMMENT 'Unit of measure for yield, scrap, and rework quantities (e.g., EA for each, KG for kilogram, M for meter, L for liter). Sourced from the SAP MM material master base unit of measure.. Valid values are `^[A-Z]{1,6}$`',
    `rework_quantity` DECIMAL(18,2) COMMENT 'Quantity of units requiring rework (reprocessing to meet specification) identified during this operation. Distinct from scrap as units are recoverable. Used for rework cost tracking, quality trend analysis, and CAPA initiation.. Valid values are `^d{1,11}(.d{1,4})?$`',
    `routing_number` STRING COMMENT 'Identifier of the manufacturing routing (Bill of Process / BoP) from which this operation was derived. Links the actual execution back to the planned routing master for variance analysis and process improvement.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `scheduled_finish_timestamp` TIMESTAMP COMMENT 'Planned finish date and time for this operation as determined by the production scheduler. Used for on-time delivery tracking, schedule adherence KPIs, and downstream operation sequencing.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `scheduled_start_timestamp` TIMESTAMP COMMENT 'Planned start date and time for this operation as determined by the production scheduler (SAP PP/DS or Opcenter Scheduling). Used for schedule adherence measurement and capacity planning variance analysis.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `scrap_quantity` DECIMAL(18,2) COMMENT 'Quantity of units scrapped (irreversibly rejected) during this operation. Feeds OEE quality rate calculation, scrap cost reporting in SAP CO, and quality management CAPA (Corrective and Preventive Action) processes.. Valid values are `^d{1,11}(.d{1,4})?$`',
    `serial_number` STRING COMMENT 'Serial number of the specific unit being processed in this operation, applicable for serialized production (e.g., ETO or high-value assemblies). Enables unit-level traceability from manufacturing through field service.. Valid values are `^[A-Z0-9-]{1,50}$`',
    `shift_code` STRING COMMENT 'Production shift during which this operation was executed (e.g., DAY, AFTERNOON, NIGHT, WEEKEND). Used for shift-level OEE analysis, labor cost allocation by shift, and production performance benchmarking across shifts.. Valid values are `^[A-Z0-9_-]{1,10}$`',
    `source_system` STRING COMMENT 'Identifies the originating operational system of record for this operation record (Siemens Opcenter MES, SAP PP, or manual entry). Supports data lineage, reconciliation between MES and ERP, and silver layer data quality management.. Valid values are `OPCENTER_MES|SAP_PP|MANUAL`',
    `spc_violation_flag` BOOLEAN COMMENT 'Indicates whether a Statistical Process Control (SPC) control chart violation (e.g., out-of-control signal) was detected during this operation. Triggers quality alert and potential hold in the MES quality module.. Valid values are `true|false`',
    `standard_run_time_min` DECIMAL(18,2) COMMENT 'Planned or standard run time in minutes for this operation as defined in the routing master. Used as the baseline for cycle time variance, OEE performance rate, and manufacturing cost standard costing.. Valid values are `^d{1,7}(.d{1,3})?$`',
    `status` STRING COMMENT 'Current execution status of the shop order operation on the shop floor. Drives WIP tracking, MES workflow routing, and production scheduling visibility. Held indicates a quality or safety stop; partially_confirmed indicates a mid-operation confirmation in SAP PP.. Valid values are `queued|active|completed|held|cancelled|partially_confirmed`',
    `takt_time_sec` DECIMAL(18,2) COMMENT 'Planned takt time in seconds for this operation, representing the rate at which products must be completed to meet customer demand. Used for line balancing, capacity planning, and lean manufacturing analysis.. Valid values are `^d{1,7}(.d{1,3})?$`',
    `work_center_code` STRING COMMENT 'Identifier of the work center (machine group, production cell, or cost center) where this operation is executed. Maps to the SAP PP Work Center master and Opcenter MES Resource. Used for capacity planning, scheduling, and cost allocation.. Valid values are `^[A-Z0-9_-]{1,20}$`',
    `yield_quantity` DECIMAL(18,2) COMMENT 'Quantity of conforming (good) units produced by this operation that pass to the next step or are completed. Core metric for OEE quality rate, first-pass yield (FPY), and production order confirmation in SAP PP.. Valid values are `^d{1,11}(.d{1,4})?$`',
    CONSTRAINT pk_shop_order_operation PRIMARY KEY(`shop_order_operation_id`)
) COMMENT 'Execution-level record for each operation performed against a production order on the shop floor (Opcenter MES Operation / SAP PP Confirmation at operation level). Tracks actual start/finish timestamps, operator ID, work center, machine ID, actual setup time, actual run time, actual labor time, yield quantity, scrap quantity, rework quantity, operation status (queued, active, completed, held), and NC (non-conformance) flag. Provides granular WIP tracking and feeds OEE calculations and actual cost confirmations.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`production_confirmation` (
    `production_confirmation_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying a production confirmation record in the Silver Layer lakehouse. Serves as the primary key for all downstream joins and lineage tracking.',
    `batch_id` BIGINT COMMENT 'Foreign key linking to production.batch. Business justification: production_confirmation references the batch produced during the confirmed operation. The FK batch_id normalizes the batch_number string reference and enables joins to batch master data for batch-leve',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Production confirmations specify where finished goods are received into inventory. Warehouse systems use this for automatic putaway task generation.',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Production confirmations are assigned to fiscal periods for period-end closing, work-in-process valuation, and cost of goods manufactured reporting. Controllers use this for monthly financial close.',
    `goods_issue_id` BIGINT COMMENT 'Foreign key linking to order.goods_issue. Business justification: Production confirmations trigger or reference goods issue documents when finished goods are transferred to fulfillment. Warehouse and production teams reconcile production output against goods issue r',
    `inspection_lot_id` BIGINT COMMENT 'Foreign key linking to quality.inspection_lot. Business justification: When a production confirmation is posted, it triggers or references an inspection lot for goods-receipt or in-process quality check. This is a standard SAP PP-QM integration used in every manufacturin',
    `measurement_reading_id` BIGINT COMMENT 'Foreign key linking to asset.measurement_reading. Business justification: When confirming production output, operators record machine counter or meter readings (e.g., press strokes, spindle hours) that update asset measurement points. This link drives usage-based maintenanc',
    `product_specification_id` BIGINT COMMENT 'Foreign key linking to engineering.product_specification. Business justification: Production confirmations record that output was verified against a specific product specification revision. Quality inspectors use this link to confirm which spec version governed the production run —',
    `routing_operation_id` BIGINT COMMENT 'Foreign key linking to production.routing_operation. Business justification: production_confirmation is posted for a specific routing_operation. The FK routing_operation_id enables joins to routing_operation master data for operation-level confirmation analysis and standard ti',
    `shift_id` BIGINT COMMENT 'Foreign key linking to production.shift. Business justification: production_confirmation is posted for a specific shift. The FK shift_id normalizes the shift string reference and enables joins to shift master data for shift-level confirmation analysis and labor tim',
    `wip_stock_id` BIGINT COMMENT 'Foreign key linking to inventory.wip_stock. Business justification: Production confirmations update WIP stock levels as operations complete. Each confirmation reduces or transfers WIP inventory, requiring a direct reference to the WIP stock record being consumed or tr',
    `work_center_id` BIGINT COMMENT 'Foreign key linking to production.work_center. Business justification: production_confirmation is posted at a specific work_center. The FK work_center_id enables joins to work_center master data for confirmation analysis and capacity utilization reporting. work_center_na',
    `actual_cost_amount` DECIMAL(18,2) COMMENT 'Actual manufacturing cost settled to the production order upon confirmation, including material, labor, machine, and overhead components. Used for actual vs. standard cost variance analysis and COGS reporting.. Valid values are `^-?d{1,14}(.d{1,4})?$`',
    `actual_finish_timestamp` TIMESTAMP COMMENT 'Actual date and time when the confirmed operation was completed on the shop floor. Combined with actual start timestamp to derive actual cycle time and compare against takt time.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `actual_labor_time_min` DECIMAL(18,2) COMMENT 'Actual labor time in minutes consumed during the confirmed operation. Used for labor cost settlement, workforce productivity analysis, and comparison against standard labor time from the routing.. Valid values are `^d{1,8}(.d{1,4})?$`',
    `actual_machine_time_min` DECIMAL(18,2) COMMENT 'Actual machine runtime in minutes consumed during the confirmed operation. Used for OEE performance rate calculation, machine utilization reporting, and actual vs. standard cost variance analysis.. Valid values are `^d{1,8}(.d{1,4})?$`',
    `actual_setup_time_min` DECIMAL(18,2) COMMENT 'Actual changeover/setup time in minutes recorded for the confirmed operation. Used for SMED analysis, OEE availability calculation, and identification of changeover reduction opportunities.. Valid values are `^d{1,8}(.d{1,4})?$`',
    `actual_start_timestamp` TIMESTAMP COMMENT 'Actual date and time when the confirmed operation began on the shop floor. Used to calculate actual cycle time, machine utilization, and OEE availability rate.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `batch_number` STRING COMMENT 'Manufacturing batch or lot number assigned to the confirmed production output. Critical for batch traceability, quality inspection lot linkage, and regulatory compliance (e.g., serialization, REACH/RoHS).. Valid values are `^[A-Z0-9-]{1,20}$`',
    `confirmed_quantity` DECIMAL(18,2) COMMENT 'Quantity of good units successfully produced and confirmed against the production order operation. Represents the yield posted to inventory. Used for OEE quality rate, throughput, and order completion percentage calculations.. Valid values are `^d{1,14}(.d{1,4})?$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the manufacturing plant where the confirmation was posted. Supports multi-country regulatory compliance reporting (e.g., CE Marking, RoHS, REACH, OSHA) and regional analytics.. Valid values are `^[A-Z]{3}$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the actual cost amount (e.g., USD, EUR, CNY). Supports multi-currency cost reporting for multinational manufacturing operations.. Valid values are `^[A-Z]{3}$`',
    `goods_movement_document_number` STRING COMMENT 'SAP material document number generated by the inventory posting (goods receipt) triggered by this production confirmation. Provides the audit trail link between the confirmation event and the resulting stock and accounting entries.. Valid values are `^[0-9]{10}$`',
    `is_auto_goods_receipt` BOOLEAN COMMENT 'Indicates whether the goods receipt (inventory posting from WIP to finished goods) was triggered automatically upon confirmation posting, as configured in the production order control key.. Valid values are `true|false`',
    `is_final_confirmation` BOOLEAN COMMENT 'Indicates whether this confirmation is the final posting for the production order operation, triggering order status change to Technically Completed (TECO) in SAP PP and closing WIP balances.. Valid values are `true|false`',
    `material_description` STRING COMMENT 'Short description of the material being confirmed, as maintained in the SAP material master. Supports self-contained reporting without requiring a material master lookup.',
    `material_number` STRING COMMENT 'SAP material master number of the finished or semi-finished product being confirmed. Links the confirmation to the product catalog, BOM, and costing records.. Valid values are `^[A-Z0-9-]{1,40}$`',
    `movement_type` STRING COMMENT 'SAP goods movement type code associated with the inventory posting triggered by this confirmation (e.g., 101 = GR for production order, 531 = GR for by-product). Determines the accounting entries and stock update logic.. Valid values are `^[0-9]{3}$`',
    `ncr_number` STRING COMMENT 'Reference to the Non-Conformance Report raised against this confirmation when scrap or rework quantities are posted. Triggers CAPA workflow and feeds the QMS for defect tracking and regulatory reporting.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `number` STRING COMMENT 'Business-facing alphanumeric identifier for the production confirmation, as assigned by SAP PP or Siemens Opcenter MES. Used for cross-system traceability and operator reference on the shop floor.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `operation_number` STRING COMMENT 'Routing operation sequence number (e.g., 0010, 0020) within the production order for which this confirmation is posted. Identifies the specific manufacturing step confirmed.. Valid values are `^[0-9]{4}$`',
    `plant_code` STRING COMMENT 'SAP plant identifier representing the manufacturing facility where the production confirmation was posted. Enables multi-plant production reporting and cross-site OEE benchmarking.. Valid values are `^[A-Z0-9]{4}$`',
    `posting_date` DATE COMMENT 'Accounting-relevant date on which the goods movement and cost settlement are posted to the general ledger. May differ from the confirmation timestamp when backdating is applied for period-end closing.. Valid values are `^d{4}-d{2}-d{2}$`',
    `production_order_number` STRING COMMENT 'Reference to the production order against which this confirmation is posted. Links shop floor execution output back to the originating manufacturing order in SAP PP.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `production_strategy` STRING COMMENT 'Manufacturing strategy under which the confirmed production order was executed: Make-to-Order (MTO), Make-to-Stock (MTS), Engineer-to-Order (ETO), or Assemble-to-Order (ATO). Drives demand linkage and inventory valuation logic.. Valid values are `MTO|MTS|ETO|ATO`',
    `quality_inspection_lot_number` STRING COMMENT 'SAP QM inspection lot number automatically created upon posting of the production confirmation. Links the confirmed output to the quality inspection process for usage decision and AQL-based sampling.. Valid values are `^[0-9]{12}$`',
    `rework_quantity` DECIMAL(18,2) COMMENT 'Quantity of units identified as requiring rework during the confirmed operation. Drives rework order creation and feeds cost-of-poor-quality (COPQ) reporting and CAPA processes.. Valid values are `^d{1,14}(.d{1,4})?$`',
    `scrap_quantity` DECIMAL(18,2) COMMENT 'Quantity of units scrapped during the confirmed operation. Triggers scrap cost postings and feeds scrap rate KPI reporting. Used in Six Sigma and Lean Manufacturing waste analysis.. Valid values are `^d{1,14}(.d{1,4})?$`',
    `shift` STRING COMMENT 'Manufacturing shift during which the production confirmation was recorded (e.g., Day, Afternoon, Night, Shift-A). Used for shift-level OEE analysis, throughput reporting, and labor cost allocation.. Valid values are `^[A-Za-z0-9-_]{1,20}$`',
    `source_system` STRING COMMENT 'Originating operational system from which the production confirmation record was extracted (e.g., SAP_PP, OPCENTER_MES, MANUAL). Supports data lineage, reconciliation, and audit trail requirements in the Silver Layer.. Valid values are `SAP_PP|OPCENTER_MES|MANUAL`',
    `status` STRING COMMENT 'Current processing status of the production confirmation record. Posted indicates successful goods movement; Reversed indicates a corrective reversal has been applied; Blocked indicates a hold pending quality or variance review.. Valid values are `posted|reversed|blocked|in_process|cancelled`',
    `storage_location_code` STRING COMMENT 'SAP storage location to which confirmed finished goods or semi-finished goods are transferred upon posting. Drives inventory placement in WMS and supports ATP/CTP calculations.. Valid values are `^[A-Z0-9]{4}$`',
    `timestamp` TIMESTAMP COMMENT 'Date and time at which the production confirmation was posted in the MES or ERP system. Serves as the authoritative completion event timestamp for WIP-to-finished-goods inventory postings and actual cost settlement.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `type` STRING COMMENT 'Indicates whether this confirmation represents a partial quantity posting, a final completion posting, a reversal of a prior confirmation, or a milestone-based confirmation. Drives order status transitions in SAP PP.. Valid values are `partial|final|reverse|milestone`',
    `unit_of_measure` STRING COMMENT 'Base unit of measure for confirmed, scrap, and rework quantities (e.g., EA, KG, L, M). Aligns with SAP material master base UoM to ensure consistent inventory and cost postings.. Valid values are `^[A-Z]{2,5}$`',
    `variance_reason_code` STRING COMMENT 'Coded reason explaining deviations from planned quantities, times, or costs (e.g., machine breakdown, material shortage, quality rejection). Feeds variance analysis in SAP CO and supports CAPA and root cause analysis.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `variance_reason_description` STRING COMMENT 'Free-text description providing additional context for the variance reason code. Captures operator or supervisor notes on deviations for root cause analysis and continuous improvement initiatives.',
    `work_center_code` STRING COMMENT 'Identifier of the work center (machine, production line, or cell) where the confirmed operation was executed. Used for capacity utilization, OEE calculation, and cost center allocation.. Valid values are `^[A-Z0-9-]{1,20}$`',
    CONSTRAINT pk_production_confirmation PRIMARY KEY(`production_confirmation_id`)
) COMMENT 'Goods confirmation record posted against a production order upon completion of production activities (SAP PP Goods Receipt / Order Confirmation). Captures confirmed quantity (yield), scrap quantity, rework quantity, confirmation timestamp, confirming operator, work center, movement type, storage location, batch number, and variance reason codes. Triggers inventory postings (WIP to finished goods), actual cost settlement, and order status updates. SSOT for production output quantities and completion events.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`material_staging` (
    `material_staging_id` BIGINT COMMENT 'Unique surrogate identifier for each material staging and issuance record on the shop floor. Serves as the primary key for the material_staging data product in the Databricks Silver Layer.',
    `batch_id` BIGINT COMMENT 'Foreign key linking to production.batch. Business justification: material_staging references the batch being issued to the shop floor. The FK batch_id normalizes the batch_number string reference and enables joins to batch master data for batch-level material flow ',
    `delivery_id` BIGINT COMMENT 'Foreign key linking to logistics.delivery. Business justification: Material staging is directly triggered by an inbound or outbound delivery document. Production planners and warehouse staff link staged materials to the delivery to confirm what has arrived and is rea',
    `goods_receipt_id` BIGINT COMMENT 'Foreign key linking to procurement.goods_receipt. Business justification: Material staging in production is directly triggered by goods receipts from procurement. Warehouse and production teams use this link to confirm that received materials are staged to the correct work ',
    `line_item_id` BIGINT COMMENT 'Foreign key linking to order.order_line_item. Business justification: Materials are staged for specific order line items in configure-to-order environments. Warehouse and production teams use this to ensure correct components are available for customer-specific configur',
    `location_id` BIGINT COMMENT 'Foreign key linking to logistics.logistics_location. Business justification: Material staging occurs at specific logistics locations (warehouses, staging areas, docks) before production. Production planners coordinate with logistics to ensure materials are positioned correctly',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Production material staging references the originating purchase order to trace which procurement document authorized the material supply. Used by production planners to resolve material shortages and ',
    `schedule_line_id` BIGINT COMMENT 'Foreign key linking to order.schedule_line. Business justification: Material staging is driven by customer order schedule lines that specify required quantities and dates. Production logistics teams stage materials against specific schedule lines to meet confirmed del',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Material staging pulls from specific storage locations. Pick lists direct warehouse staff to exact bin locations for production material retrieval.',
    `work_center_id` BIGINT COMMENT 'Foreign key linking to production.work_center. Business justification: material_staging.work_center_code (STRING) is a denormalized reference to the work_center master. Material staging records are associated with the work center to which materials are being staged (supp',
    `actual_staging_timestamp` TIMESTAMP COMMENT 'Actual date and time when the material was physically moved to the staging area or production supply area. Captured by MES or WMS system. Used for staging lead time analysis and JIT performance measurement.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}T[0-9]{2}:[0-9]{2}:[0-9]{2}.[0-9]{3}[+-][0-9]{2}:[0-9]{2}$`',
    `backflush_indicator` BOOLEAN COMMENT 'Indicates whether the material is subject to backflushing (automatic goods issue upon production order confirmation) rather than manual goods issue. Backflushed components do not require explicit staging transactions.. Valid values are `true|false`',
    `batch_number` STRING COMMENT 'Batch or lot number (SAP CHARG) of the material being staged or issued. Critical for batch-managed materials, traceability, quality management, and regulatory compliance (e.g., RoHS, REACH).',
    `bom_component_position` STRING COMMENT 'Position or item number of the component within the Bill of Materials (BOM) for the production order. Enables traceability from the staged material back to the BOM structure in PLM/ERP.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the manufacturing plant where the staging event occurred (e.g., USA, DEU, CHN). Supports multinational regulatory compliance, REACH/RoHS jurisdiction tracking, and regional reporting.. Valid values are `^[A-Z]{3}$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the material cost values (e.g., USD, EUR, GBP, CNY). Supports multi-currency operations across global manufacturing plants.. Valid values are `^[A-Z]{3}$`',
    `goods_issue_timestamp` TIMESTAMP COMMENT 'Date and time when the formal goods issue (SAP movement type 261) was posted in SAP S/4HANA, confirming material consumption against the production order. Triggers WIP cost update and inventory reduction.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}T[0-9]{2}:[0-9]{2}:[0-9]{2}.[0-9]{3}[+-][0-9]{2}:[0-9]{2}$`',
    `hazardous_material_indicator` BOOLEAN COMMENT 'Indicates whether the staged material is classified as hazardous under applicable regulations (e.g., REACH, RoHS, OSHA HazCom). Triggers additional handling, documentation, and safety protocols on the shop floor.. Valid values are `true|false`',
    `issued_quantity` DECIMAL(18,2) COMMENT 'Actual quantity of material formally issued to the production order via SAP Goods Issue (movement type 261). Represents confirmed material consumption posted to the production order and used for WIP costing.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `issuing_warehouse` STRING COMMENT 'Identifier of the warehouse or warehouse complex (SAP WM Warehouse Number / Infor WMS Warehouse) from which the material is physically picked and issued to the shop floor. Supports WMS integration.',
    `kanban_card_number` STRING COMMENT 'Kanban card or container identifier associated with this material staging record when the replenishment_strategy is Kanban. Links the staging event to the Kanban control cycle for pull-based replenishment tracking.',
    `material_cost_per_unit` DECIMAL(18,2) COMMENT 'Standard or moving average cost per unit of the material at the time of goods issue, as valuated in SAP S/4HANA CO. Used for WIP costing, COGS calculation, and production order cost analysis.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `movement_type` STRING COMMENT 'SAP inventory movement type code (BWART) associated with the staging or issuance transaction. Common values: 261 (Goods Issue to Production Order), 262 (Reversal of GI), 311 (Transfer to Production Storage Location), 312 (Reversal of Transfer).. Valid values are `^[0-9]{3}$`',
    `planned_staging_date` DATE COMMENT 'Planned date on which the material should be staged or issued to the shop floor, as determined by MRP II scheduling and production order requirements. Used for material availability planning.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}$`',
    `plant_code` STRING COMMENT 'SAP plant code (WERKS) identifying the manufacturing facility where the material staging and issuance takes place. Supports multi-plant, multinational operations.. Valid values are `^[A-Z0-9]{1,4}$`',
    `production_order_number` STRING COMMENT 'Reference to the production order (SAP PP Production Order / Process Order) for which materials are being staged or issued. Links material consumption to the manufacturing execution context.',
    `production_strategy` STRING COMMENT 'Manufacturing production strategy under which the production order was created: MTO (Make to Order), MTS (Make to Stock), ETO (Engineer to Order), or ATO (Assemble to Order). Determines material planning and staging behavior.. Valid values are `MTO|MTS|ETO|ATO`',
    `replenishment_strategy` STRING COMMENT 'Material replenishment strategy governing how this component is supplied to the shop floor. Supports JIT (Just-In-Time), Kanban pull-based replenishment, MRP-driven push replenishment, manual staging, or consignment stock.. Valid values are `JIT|Kanban|MRP|manual|consignment`',
    `required_quantity` DECIMAL(18,2) COMMENT 'Planned quantity of the material required for the production order as specified in the BOM or reservation. Represents the demand quantity before actual issuance. Used for shortage analysis and MRP II planning.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `reservation_line` STRING COMMENT 'Line item within the material reservation corresponding to the specific component being staged. Used to match the staging record to the exact reservation item in SAP.. Valid values are `^[0-9]{1,4}$`',
    `reservation_number` STRING COMMENT 'SAP reservation number (RSNUM) created by MRP or production order release, representing the planned material requirement that this staging record fulfills. Supports JIT and MRP II material planning workflows.',
    `reversal_timestamp` TIMESTAMP COMMENT 'Date and time when a goods issue reversal (SAP movement type 262) was posted, cancelling a previously issued quantity. Applicable only when staging_status is reversed. Supports audit trail and WIP cost correction.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}T[0-9]{2}:[0-9]{2}:[0-9]{2}.[0-9]{3}[+-][0-9]{2}:[0-9]{2}$`',
    `serial_number` STRING COMMENT 'Serial number of the specific component unit being issued, applicable for serialized materials. Supports unit-level traceability and asset lifecycle management.',
    `short_quantity` DECIMAL(18,2) COMMENT 'Quantity of material that could not be staged or issued due to insufficient stock (shortage). Calculated as required_quantity minus issued_quantity when status is short. Drives material shortage alerts and expediting actions.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `shortage_indicator` BOOLEAN COMMENT 'Boolean flag indicating whether a material shortage exists for this staging record (i.e., required_quantity cannot be fully fulfilled from available stock). Drives shortage alerts, expediting, and JIT replenishment triggers.. Valid values are `true|false`',
    `source_system` STRING COMMENT 'Operational system of record from which this material staging record originated. Identifies whether the record was created in SAP S/4HANA PP/MM, Siemens Opcenter MES, Infor WMS, or entered manually. Supports data lineage in the Databricks Silver Layer.. Valid values are `SAP_S4HANA|OPCENTER_MES|INFOR_WMS|MANUAL`',
    `staged_quantity` DECIMAL(18,2) COMMENT 'Quantity of material physically moved to the staging area or production supply area (PSA) but not yet formally issued via goods issue posting. Represents the intermediate staging step in JIT and Kanban workflows.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `staging_document_line` STRING COMMENT 'Line item number within the staging document, identifying the specific component or material being staged or issued within a multi-line goods issue document.. Valid values are `^[0-9]{1,4}$`',
    `staging_document_number` STRING COMMENT 'Business document number assigned by SAP S/4HANA (PP/MM) to the goods issue or material staging transaction. Corresponds to the SAP Material Document Number (MBLNR) generated upon goods issue posting.',
    `staging_document_year` STRING COMMENT 'Fiscal year associated with the staging document number in SAP S/4HANA. Required to uniquely identify a material document in conjunction with the document number.. Valid values are `^[0-9]{4}$`',
    `staging_status` STRING COMMENT 'Current lifecycle status of the material staging record. planned = reservation created; staged = material moved to staging area; issued = goods issue posted; short = insufficient stock; partially_issued = partial goods issue; reversed = goods issue reversed; cancelled = staging cancelled.. Valid values are `planned|staged|issued|short|partially_issued|reversed|cancelled`',
    `storage_location` STRING COMMENT 'SAP storage location (LGORT) from which the material is staged or issued. Identifies the physical warehouse or shop floor storage area within the plant from which inventory is consumed.. Valid values are `^[A-Z0-9]{1,4}$`',
    `supply_area` STRING COMMENT 'SAP Production Supply Area (PSA) or line-side staging location where the material is delivered for shop floor consumption. Represents the physical destination on the shop floor for staged materials.',
    `total_issued_cost` DECIMAL(18,2) COMMENT 'Total cost of the issued material quantity (issued_quantity × material_cost_per_unit) in the transaction currency. Feeds WIP costing, production order actual cost, and COGS reporting.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `unit_of_measure` STRING COMMENT 'Base unit of measure (SAP MEINS) for the material quantities (required, staged, issued, short). Examples: EA (each), KG (kilogram), L (liter), M (meter), M2 (square meter). Ensures consistent quantity reporting.. Valid values are `^[A-Z]{1,6}$`',
    `valuation_type` STRING COMMENT 'Costing method used to value the issued material: standard cost (fixed standard price), moving average price (MAP), or actual cost. Determines how WIP and COGS are calculated for the production order.. Valid values are `standard_cost|moving_average|actual_cost`',
    CONSTRAINT pk_material_staging PRIMARY KEY(`material_staging_id`)
) COMMENT 'Records the staging and issuance of raw materials and components from inventory to the shop floor for a production order (SAP PP Goods Issue / Material Staging). Stores production order reference, component material number, required quantity, issued quantity, staging date/time, storage location, batch number, issuing warehouse, and staging status (planned, staged, issued, short). Tracks material availability on the shop floor and feeds WIP costing. Supports JIT and Kanban material replenishment workflows.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`order_status` (
    `order_status_id` BIGINT COMMENT 'Unique surrogate identifier for each production order status transition event record in the Silver layer lakehouse.',
    `batch_id` BIGINT COMMENT 'Foreign key linking to production.batch. Business justification: order_status snapshots reference the batch associated with the production order at the time of status transition. The FK batch_id normalizes the batch_number string reference and enables joins to batc',
    `order_type_id` BIGINT COMMENT 'Foreign key linking to production.order_type. Business justification: order_status.production_order_type (STRING) is a denormalized reference to the order_type master. Adding order_type_id FK normalizes this, allowing status lifecycle records to be filtered and analyzed',
    `routing_id` BIGINT COMMENT 'Foreign key linking to production.routing. Business justification: order_status.routing_number (STRING) is a denormalized reference to the routing master. Production order status lifecycle records are associated with a specific routing that defines the operations bei',
    `work_center_id` BIGINT COMMENT 'Foreign key linking to production.work_center. Business justification: order_status.work_center_code (STRING) is a denormalized reference to the work_center master. Status transitions on production orders are often associated with a specific work center (e.g., a HOLD sta',
    `actual_finish_timestamp` TIMESTAMP COMMENT 'The actual date and time when production execution was completed for this order, as recorded in Opcenter MES or SAP PP technical completion. Used to calculate actual cycle time and on-time delivery performance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `actual_start_timestamp` TIMESTAMP COMMENT 'The actual date and time when production execution began for this order, as recorded in Opcenter MES or SAP PP confirmation. Used to calculate actual lead time and schedule variance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `batch_number` STRING COMMENT 'The production batch or lot number associated with the production order at the time of the status transition. Critical for batch traceability, recall management, and GMP compliance.',
    `company_code` STRING COMMENT 'SAP company code representing the legal entity responsible for the production order. Supports multi-entity financial reporting, IFRS/GAAP compliance, and intercompany manufacturing scenarios.. Valid values are `^[A-Z0-9]{2,6}$`',
    `confirmed_quantity` DECIMAL(18,2) COMMENT 'The cumulative quantity of the production order that has been confirmed (goods receipt posted) at the time of the status transition. Enables partial completion tracking and yield analysis.',
    `cost_center_code` STRING COMMENT 'SAP cost center associated with the production order at the time of the status transition. Supports COGS allocation, production cost tracking, and financial controlling.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant or manufacturing site where the production order status transition occurred. Supports multinational regulatory compliance and regional performance reporting.. Valid values are `^[A-Z]{3}$`',
    `duration_minutes` DECIMAL(18,2) COMMENT 'The elapsed time in minutes that the production order spent in the from_status before transitioning to the to_status. Enables dwell time analysis, bottleneck identification, and SLA breach detection.',
    `from_status` STRING COMMENT 'The production order status immediately before the transition event. Represents the prior lifecycle state as recorded in SAP PP or Opcenter MES (e.g., CREATED, RELEASED, IN_PROCESS).. Valid values are `CREATED|RELEASED|PARTIALLY_CONFIRMED|CONFIRMED|TECHNICALLY_COMPLETED|CLOSED|DELETED|QM_HOLD|SCHEDULED|IN_PROCESS|PARTIALLY_DELIVERED|LOCKED`',
    `is_sla_breached` BOOLEAN COMMENT 'Indicates whether the production order exceeded its defined SLA target duration at the time of this status transition. Drives escalation workflows and production performance KPI reporting.. Valid values are `true|false`',
    `material_description` STRING COMMENT 'Short description of the material or finished product being manufactured, as maintained in the SAP material master. Provides human-readable context for reporting without requiring a join.',
    `material_number` STRING COMMENT 'SAP material number (SKU) of the finished good or semi-finished product being manufactured by this production order. Links the status history to the product being produced.',
    `mes_operation_number` STRING COMMENT 'The specific MES operation or activity number within the production order routing that was active or completed at the time of the status transition. Provides granular shop floor execution context.',
    `ncr_number` STRING COMMENT 'Reference to the Non-Conformance Report (NCR) that triggered a QM hold or rework status transition. Enables traceability between production order status events and quality non-conformances.',
    `order_category` STRING COMMENT 'SAP order category distinguishing production orders (discrete manufacturing), process orders (batch/process manufacturing), maintenance orders, rework orders, and inspection orders.. Valid values are `PRODUCTION|PROCESS|MAINTENANCE|REWORK|INSPECTION`',
    `order_quantity` DECIMAL(18,2) COMMENT 'The total planned production quantity for the order at the time of the status transition. Captures the order size context for throughput and capacity analysis.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility where the production order is being executed. Supports multi-plant and multinational reporting.. Valid values are `^[A-Z0-9]{2,6}$`',
    `priority_code` STRING COMMENT 'The business priority assigned to the production order, influencing scheduling and resource allocation decisions. EXPEDITE indicates customer-driven urgency or supply chain escalation.. Valid values are `CRITICAL|HIGH|MEDIUM|LOW|EXPEDITE`',
    `production_order_number` STRING COMMENT 'The business key of the production order (SAP PP order number or Opcenter work order number) whose status is being tracked. Serves as the primary cross-system reference for the order lifecycle.',
    `profit_center_code` STRING COMMENT 'SAP profit center assigned to the production order, enabling cost and revenue attribution by business unit or product line for management accounting and EBITDA reporting.',
    `qm_inspection_lot_number` STRING COMMENT 'The SAP QM inspection lot number associated with this status transition when the trigger is a quality hold, quality release, or inspection result. Links production order status to quality inspection outcomes.',
    `quantity_unit_of_measure` STRING COMMENT 'The unit of measure for the order quantity (e.g., EA for each, KG for kilogram, PC for piece). Ensures correct interpretation of quantity values across materials.. Valid values are `EA|KG|LB|L|M|M2|M3|PC|SET|BOX|ROLL|TON`',
    `record_created_timestamp` TIMESTAMP COMMENT 'The timestamp when this status transition record was created in the Silver layer lakehouse. Supports data lineage, audit trail, and incremental load processing.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `record_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this status transition record was last updated in the Silver layer lakehouse. Supports change tracking, data quality monitoring, and SCD Type 1 correction scenarios.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `scheduled_finish_date` DATE COMMENT 'The planned completion date of the production order as scheduled in SAP PP or Opcenter MES at the time of the status transition. Baseline for on-time delivery and SLA compliance measurement.. Valid values are `^d{4}-d{2}-d{2}$`',
    `scheduled_start_date` DATE COMMENT 'The planned start date of the production order as scheduled in SAP PP or Opcenter MES at the time of the status transition. Used for schedule adherence and lead time SLA tracking.. Valid values are `^d{4}-d{2}-d{2}$`',
    `scrap_quantity` DECIMAL(18,2) COMMENT 'The quantity of production output declared as scrap at the time of the status transition. Used for scrap rate calculation and quality performance reporting.',
    `sla_target_hours` DECIMAL(18,2) COMMENT 'The contracted or internally defined SLA target duration in hours for the production order to complete from release to technical completion. Used to assess whether the order met its lead time commitment.',
    `source_system` STRING COMMENT 'The originating operational system that generated or recorded this status transition event (e.g., SAP_PP for ERP-driven transitions, OPCENTER_MES for shop floor-driven transitions). Supports data lineage and reconciliation.. Valid values are `SAP_PP|OPCENTER_MES|MANUAL|ERP_INTEGRATION|MRP_RUN`',
    `source_system_event_code` STRING COMMENT 'The unique event or change document identifier from the originating source system (SAP change document number or Opcenter event ID) for this status transition. Enables traceability back to the system of record.',
    `status_reason_code` STRING COMMENT 'Standardized reason code explaining why the status transition occurred (e.g., MATERIAL_SHORTAGE, CAPACITY_CONSTRAINT, QM_INSPECTION_FAIL, CUSTOMER_CHANGE, PLANNED_MAINTENANCE). Supports root cause analysis and production performance reporting.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `status_reason_description` STRING COMMENT 'Free-text description providing additional context for the status transition reason, supplementing the structured reason code. Allows planners and supervisors to document specific circumstances.',
    `to_status` STRING COMMENT 'The production order status immediately after the transition event. Represents the new lifecycle state the order has entered (e.g., RELEASED, TECHNICALLY_COMPLETED, CLOSED).. Valid values are `CREATED|RELEASED|PARTIALLY_CONFIRMED|CONFIRMED|TECHNICALLY_COMPLETED|CLOSED|DELETED|QM_HOLD|SCHEDULED|IN_PROCESS|PARTIALLY_DELIVERED|LOCKED`',
    `transition_timestamp` TIMESTAMP COMMENT 'The exact date and time (with timezone offset) at which the status transition occurred. Critical for SLA tracking, lead time calculation, and audit trail compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `trigger_event_type` STRING COMMENT 'The business event or system action that caused the status transition (e.g., MRP run, manual release by planner, system confirmation from MES, QM hold from quality inspection). Enables root cause analysis of order lifecycle events.. Valid values are `MRP_RUN|MANUAL_RELEASE|SYSTEM_CONFIRMATION|QM_HOLD|QM_RELEASE|GOODS_RECEIPT|PARTIAL_CONFIRMATION|TECHNICAL_COMPLETION|ORDER_CLOSE|ORDER_DELETE|SCHEDULE_CHANGE|LOCK|UNLOCK|BATCH_RELEASE|ERP_INTEGRATION`',
    `triggered_by_user` STRING COMMENT 'The SAP or Opcenter user ID of the person or system account that initiated the status transition. Used for accountability, audit trail, and change management compliance.',
    CONSTRAINT pk_order_status PRIMARY KEY(`order_status_id`)
) COMMENT 'Lifecycle status history of production orders, capturing every status transition event from creation through closure (SAP PP Order Status / Opcenter Work Order Status History). Stores production order reference, from-status, to-status, transition timestamp, triggered-by user, triggering event (MRP run, manual release, system confirmation, QM hold), and status reason code. Enables full audit trail of order lifecycle, supports SLA tracking for order lead times, and feeds production performance reporting.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`capacity_requirement` (
    `capacity_requirement_id` BIGINT COMMENT 'Unique surrogate identifier for each capacity requirement record generated by MRP II capacity planning in SAP PP (CM01). Serves as the primary key for the capacity_requirement data product in the Databricks Silver layer.',
    `forecast_id` BIGINT COMMENT 'Foreign key linking to sales.forecast. Business justification: Capacity requirements planning (CRP) derives load from sales forecasts. Planners trace capacity needs back to the originating forecast to validate whether the plant can meet projected sales demand.',
    `fulfillment_plan_id` BIGINT COMMENT 'Foreign key linking to order.fulfillment_plan. Business justification: Capacity requirements are calculated from demand represented in fulfillment plans. Capacity planners trace capacity loads back to fulfillment plans to identify bottlenecks caused by specific customer ',
    `maintenance_plan_id` BIGINT COMMENT 'Foreign key linking to asset.maintenance_plan. Business justification: Capacity planners must account for planned maintenance windows when calculating available machine capacity. Linking capacity requirements to maintenance plans ensures production scheduling respects pr',
    `mrp_run_id` BIGINT COMMENT 'Foreign key linking to procurement.mrp_run. Business justification: Capacity requirements are calculated as a direct output of an MRP run. Production planners must trace which MRP run generated each capacity requirement to validate planning results and resolve overloa',
    `production_order_cost_id` BIGINT COMMENT 'Foreign key linking to finance.production_order_cost. Business justification: Capacity requirements carry planned activity costs (machine hours × cost rate) that feed into the production order cost object. Cost planners use this link to build the planned cost structure for manu',
    `routing_id` BIGINT COMMENT 'Foreign key linking to production.routing. Business justification: capacity_requirement is generated by MRP II for specific routings. The FK routing_id normalizes the routing_number string reference and enables joins to routing master data for capacity planning analy',
    `routing_operation_id` BIGINT COMMENT 'Foreign key linking to production.routing_operation. Business justification: capacity_requirement is computed per routing_operation for detailed capacity planning. The FK routing_operation_id normalizes the routing_operation_number string reference and enables joins to routing',
    `shift_id` BIGINT COMMENT 'Foreign key linking to production.shift. Business justification: capacity_requirement is planned per shift for detailed capacity analysis. The FK shift_id normalizes the shift_code reference and enables joins to shift master data for shift-level capacity load analy',
    `work_center_id` BIGINT COMMENT 'FK to production.work_center',
    `available_capacity_hours` DECIMAL(18,2) COMMENT 'Total capacity (in hours) available at the work center during the planning period, derived from the work centers capacity definition and shift model in SAP PP. Used to compute load percentage and identify overloads.. Valid values are `^d+(.d{1,4})?$`',
    `capacity_category_code` STRING COMMENT 'SAP capacity category code distinguishing the type of capacity being planned (e.g., machine capacity, labor capacity, tool capacity). Corresponds to SAP PP capacity category (e.g., 001 = Machine, 002 = Labor).',
    `capacity_category_name` STRING COMMENT 'Human-readable description of the capacity category (Machine, Labor, Tool, Other). Used for filtering and grouping in capacity leveling and bottleneck analysis.. Valid values are `Machine|Labor|Tool|Other`',
    `capacity_unit_of_measure` STRING COMMENT 'Unit of measure in which capacity requirements and availability are expressed (e.g., H = Hours, MIN = Minutes). Ensures consistent interpretation of capacity figures across work centers.. Valid values are `H|MIN|PC|KG|M`',
    `capacity_version` STRING COMMENT 'SAP planning version identifier (e.g., 000 for active version, simulation versions) under which this capacity requirement was calculated. Enables what-if scenario management and simulation-based capacity planning.',
    `cost_center_code` STRING COMMENT 'SAP Controlling (CO) cost center code associated with the work center. Enables financial allocation of capacity costs and integration with OPEX reporting.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant where the work center is located. Supports multi-country capacity reporting and compliance with regional labor regulations.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the capacity requirement record was first created in the source system (SAP PP) or ingested into the Silver layer. Supports data lineage, audit trail, and incremental load processing.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `efficiency_rate` DECIMAL(18,2) COMMENT 'Efficiency factor (as a percentage) applied to the work center when calculating available capacity, reflecting the expected productive utilization rate (e.g., 85% efficiency means 85% of nominal capacity is available). Sourced from SAP PP work center definition.. Valid values are `^d+(.d{1,4})?$`',
    `is_overloaded` BOOLEAN COMMENT 'Flag indicating whether the work center is overloaded during the planning period (required capacity exceeds available capacity). Triggers capacity leveling actions and what-if scheduling scenarios.. Valid values are `true|false`',
    `last_changed_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the capacity requirement record in the source system or Silver layer. Used for change detection, incremental ETL, and audit trail compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `leveling_action` STRING COMMENT 'Action taken during capacity leveling to resolve an overload condition at the work center (e.g., Rescheduled, Split, Outsourced, Overtime, Deferred). Supports audit trail of capacity leveling decisions.. Valid values are `None|Rescheduled|Split|Outsourced|Overtime|Deferred`',
    `load_percentage` DECIMAL(18,2) COMMENT 'Ratio of required capacity to available capacity expressed as a percentage (required_capacity_hours / available_capacity_hours × 100). Key indicator for bottleneck identification and capacity leveling decisions.. Valid values are `^d+(.d{1,4})?$`',
    `mrp_run_date` DATE COMMENT 'Date on which the MRP II planning run was executed that generated this capacity requirement record. Enables time-series comparison of capacity plans across successive MRP runs.. Valid values are `^d{4}-d{2}-d{2}$`',
    `mrp_run_number` STRING COMMENT 'Unique identifier of the MRP II planning run that generated this capacity requirement. Supports audit traceability and comparison between planning runs for what-if scenario analysis.',
    `notes` STRING COMMENT 'Free-text field for planner annotations, leveling justifications, or exception comments related to the capacity requirement record. Supports operational communication and audit documentation.',
    `number_of_resources` STRING COMMENT 'Number of individual machines, operators, or tools at the work center contributing to the available capacity for this planning period. Used to calculate per-resource load and support headcount/machine planning.. Valid values are `^d+$`',
    `order_count` STRING COMMENT 'Number of production orders and planned orders contributing to the capacity requirement for this work center and planning period. Indicates the complexity of the load and supports scheduling prioritization.. Valid values are `^d+$`',
    `overload_hours` DECIMAL(18,2) COMMENT 'Number of hours by which required capacity exceeds available capacity during the planning period. Quantifies the severity of the overload for prioritization and leveling decisions.',
    `planned_order_hours` DECIMAL(18,2) COMMENT 'Capacity hours contributed by MRP-generated planned orders (not yet converted to production orders) within the planning period. Distinguishes firm demand from planned demand for capacity analysis.. Valid values are `^d+(.d{1,4})?$`',
    `planning_horizon_type` STRING COMMENT 'Granularity of the planning time bucket used for capacity aggregation (Daily, Weekly, Monthly). Determines the resolution of capacity load visibility for scheduling and leveling.. Valid values are `Daily|Weekly|Monthly`',
    `planning_period_end_date` DATE COMMENT 'End date of the planning period for which the capacity requirement is calculated. Together with planning_period_start_date, defines the time bucket for capacity load aggregation.. Valid values are `^d{4}-d{2}-d{2}$`',
    `planning_period_start_date` DATE COMMENT 'Start date of the planning period (day, week, or shift bucket) for which the capacity requirement is calculated. Defines the time horizon of the capacity load record.. Valid values are `^d{4}-d{2}-d{2}$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility for which the capacity requirement is calculated. Enables multi-plant capacity visibility across the enterprise.. Valid values are `^[A-Z0-9]{1,4}$`',
    `processing_hours` DECIMAL(18,2) COMMENT 'Portion of the required capacity hours attributable to actual production/processing activities (machine run time or labor operation time) at the work center during the planning period.. Valid values are `^d+(.d{1,4})?$`',
    `production_order_hours` DECIMAL(18,2) COMMENT 'Capacity hours contributed by firm production orders (released or confirmed) within the planning period. Represents committed capacity load as opposed to planned/tentative demand.. Valid values are `^d+(.d{1,4})?$`',
    `remaining_capacity_hours` DECIMAL(18,2) COMMENT 'Residual available capacity hours after subtracting required capacity from available capacity (available_capacity_hours − required_capacity_hours). Negative values indicate overload conditions.',
    `required_capacity_hours` DECIMAL(18,2) COMMENT 'Total capacity (in hours) required at the work center during the planning period, as calculated by MRP II from open production orders and planned orders. Core metric for capacity load analysis.. Valid values are `^d+(.d{1,4})?$`',
    `requirement_number` STRING COMMENT 'Business-facing unique identifier for the capacity requirement record as assigned by SAP PP capacity planning (CM01). Used for cross-system traceability and operational reference.',
    `routing_number` STRING COMMENT 'Identifier of the production routing (Bill of Process) from which the work center operation and capacity requirement was derived. Links capacity requirements to the engineering routing definition.',
    `routing_operation_number` STRING COMMENT 'Specific operation number within the routing that generates the capacity requirement at this work center. Enables operation-level capacity traceability within a multi-step routing.',
    `setup_hours` DECIMAL(18,2) COMMENT 'Portion of the required capacity hours attributable to setup/changeover activities at the work center during the planning period. Supports SMED analysis and setup time reduction initiatives.. Valid values are `^d+(.d{1,4})?$`',
    `shift_code` STRING COMMENT 'Identifier of the production shift (e.g., Day, Afternoon, Night) within the planning period. Enables shift-level capacity load analysis and scheduling.',
    `status` STRING COMMENT 'Current status of the capacity requirement record indicating its planning state: Active (current plan), Leveled (capacity leveling applied), Overloaded (exceeds available capacity), Cancelled (order cancelled), or Simulated (what-if scenario).. Valid values are `Active|Leveled|Overloaded|Cancelled|Simulated`',
    `teardown_hours` DECIMAL(18,2) COMMENT 'Portion of the required capacity hours attributable to teardown/cleanup activities at the work center during the planning period. Included in total capacity requirement calculations.. Valid values are `^d+(.d{1,4})?$`',
    `utilization_rate` DECIMAL(18,2) COMMENT 'Utilization factor (as a percentage) applied to the work center capacity, representing the proportion of available time the resource is scheduled for productive work. Sourced from SAP PP work center definition.. Valid values are `^d+(.d{1,4})?$`',
    `work_center_code` STRING COMMENT 'Identifier of the work center (machine group, production cell, or labor pool) for which the capacity requirement is calculated. Corresponds to the SAP PP work center object (CR01/CR02).',
    CONSTRAINT pk_capacity_requirement PRIMARY KEY(`capacity_requirement_id`)
) COMMENT 'Capacity requirement records generated by MRP II capacity planning for each work center and time period (SAP PP Capacity Requirements / CM01). Stores work center, planning period (date/shift), required capacity (hours), available capacity (hours), load percentage, order references contributing to the load, capacity category (machine, labor), and overload indicator. Enables capacity leveling, bottleneck identification, and what-if scheduling scenarios. SSOT for work center capacity load visibility.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`version` (
    `version_id` BIGINT COMMENT 'Unique surrogate identifier for the production version record in the lakehouse Silver layer. Serves as the primary key for this entity.',
    `bop_id` BIGINT COMMENT 'Foreign key linking to engineering.bop. Business justification: Production versions link to Bill of Process defining manufacturing operations sequence. Production engineering uses this to establish work center routings and cycle times.',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: A production version (BOM/routing revision) is created or superseded by an Engineering Change Notice. Production control teams use this link to know which ECN triggered a version change and when to cu',
    `engineering_bom_id` BIGINT COMMENT 'Foreign key linking to engineering.bom. Business justification: Production versions define valid BOM alternatives for manufacturing. Production planning uses this to select cost-optimal or capacity-optimal manufacturing configurations.',
    `routing_id` BIGINT COMMENT 'Foreign key linking to production.routing. Business justification: A production version (SAP PP Production Version) defines the valid combination of a BOM and a routing for manufacturing a material. version currently references routing via denormalized string attribu',
    `apqp_status` STRING COMMENT 'The APQP approval status for this production version, indicating whether the manufacturing process has been formally validated through the Advanced Product Quality Planning process. Required for automotive and regulated manufacturing.. Valid values are `not_started|in_progress|approved|conditionally_approved|rejected`',
    `bom_alternative` STRING COMMENT 'The BOM alternative number (STLAL) assigned to this production version. Multiple BOM alternatives can exist for the same material, each representing a different component configuration or manufacturing method.. Valid values are `^[A-Z0-9]{1,2}$`',
    `bom_explosion_type` STRING COMMENT 'Defines how the BOM is exploded during MRP II planning and production order creation for this version: single-level (one level only), multi-level (full BOM tree), or phantom (virtual assembly, components passed through).. Valid values are `single_level|multi_level|phantom`',
    `bom_usage` STRING COMMENT 'SAP BOM usage key (STLAN) indicating the application area for which the BOM is defined (e.g., 1=Production, 5=Sales, 6=Costing). Determines which BOM is selected during production order creation.. Valid values are `^[1-9]$`',
    `change_number` STRING COMMENT 'The Engineering Change Number (ECN) or Engineering Change Order (ECO) reference that authorized the creation or last modification of this production version. Provides traceability to the change management process in Siemens Teamcenter PLM.',
    `code` STRING COMMENT 'The alphanumeric production version identifier (VERID) as defined in SAP PP. Uniquely identifies a specific BOM/routing combination for a material-plant combination. Enables multiple manufacturing methods for the same product.. Valid values are `^[A-Z0-9]{1,4}$`',
    `costing_lot_size` DECIMAL(18,2) COMMENT 'The reference lot size used for product cost calculation (standard cost estimate) for this production version. Determines the per-unit cost allocation of fixed setup and overhead costs.. Valid values are `^d+(.d{1,3})?$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant where this production version is applicable. Supports multi-country regulatory compliance, reporting, and regional manufacturing strategy analysis.. Valid values are `^[A-Z]{3}$`',
    `created_by_user` STRING COMMENT 'The SAP user ID of the person who created this production version record. Supports accountability, audit trail, and change management traceability.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this production version record was first created in the source SAP system. Used for audit trail, data lineage, and change history analysis.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `default_version` BOOLEAN COMMENT 'Indicates whether this is the default (preferred) production version for the material-plant combination. When multiple versions are valid, MRP II and production planners use the default version unless overridden.. Valid values are `true|false`',
    `deletion_flag` BOOLEAN COMMENT 'Indicates whether this production version has been flagged for deletion in the source SAP system (MKAL.LOEKZ). A flagged version is excluded from MRP II planning and production order creation but retained for historical traceability.. Valid values are `true|false`',
    `description` STRING COMMENT 'Short descriptive text explaining the purpose or distinguishing characteristics of this production version (e.g., Standard Line A Process, High-Volume Variant, Pilot Run Method).',
    `in_house_production_time_days` DECIMAL(18,2) COMMENT 'The total in-house production lead time in working days for this production version. Used by MRP II to calculate planned order dates and available-to-promise (ATP) commitments.. Valid values are `^d+(.d{1,2})?$`',
    `issue_storage_location` STRING COMMENT 'The SAP storage location (LGORT) from which components are issued to the production order for this version. Drives goods movement and WIP inventory tracking on the shop floor.. Valid values are `^[A-Z0-9]{1,4}$`',
    `last_changed_by_user` STRING COMMENT 'The SAP user ID of the person who last modified this production version record. Supports accountability, audit trail, and change management traceability.',
    `last_changed_timestamp` TIMESTAMP COMMENT 'The date and time when this production version record was last modified in the source SAP system. Supports change tracking, audit compliance, and incremental data loading in the lakehouse.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `lot_size_max` DECIMAL(18,2) COMMENT 'The maximum production lot size (MABST) for which this production version is valid. MRP II will not propose this version for planned orders exceeding this quantity. Enables capacity-constrained version selection.. Valid values are `^d+(.d{1,3})?$`',
    `lot_size_min` DECIMAL(18,2) COMMENT 'The minimum production lot size (MTVFP/MABST) for which this production version is valid. MRP II will not propose this version for planned orders below this quantity. Supports lot-size-dependent manufacturing method selection.. Valid values are `^d+(.d{1,3})?$`',
    `lot_size_unit` STRING COMMENT 'The unit of measure (MEINS) applicable to the minimum and maximum lot size values for this production version (e.g., EA, KG, L, M). Aligns with the base unit of measure of the material.. Valid values are `^[A-Z]{2,3}$`',
    `material_description` STRING COMMENT 'Short description of the material (MAKTX) for which this production version is defined. Provides human-readable context for reporting and analytics without requiring a join to the material master.',
    `material_number` STRING COMMENT 'The SAP material number (MATNR) identifying the finished or semi-finished product for which this production version is defined. Aligns with the material master in SAP MM.. Valid values are `^[A-Z0-9-_]{1,40}$`',
    `mrp_relevance` BOOLEAN COMMENT 'Indicates whether this production version is considered by MRP II during planning runs. When false, the version is excluded from automatic planned order generation even if it is within its validity period.. Valid values are `true|false`',
    `plant_code` STRING COMMENT 'SAP plant code (WERKS) identifying the manufacturing facility where this production version is valid. A production version is always plant-specific.. Valid values are `^[A-Z0-9]{1,4}$`',
    `ppap_level` STRING COMMENT 'The PPAP submission level required or achieved for this production version. Defines the extent of documentation and sample submission required to validate the manufacturing process for customer approval.. Valid values are `level_1|level_2|level_3|level_4|level_5|not_required`',
    `priority` STRING COMMENT 'Numeric priority ranking used to determine the preferred production version when multiple versions are valid for the same lot size range and validity period. Lower number indicates higher priority.. Valid values are `^[1-9][0-9]*$`',
    `production_line` STRING COMMENT 'The specific production line or work center group (ARBPL) designated for this production version. Used in repetitive manufacturing and rate-based scheduling to assign the version to a physical line.',
    `production_strategy` STRING COMMENT 'The manufacturing strategy applicable to this production version: Make-to-Order (MTO), Make-to-Stock (MTS), Engineer-to-Order (ETO), or Assemble-to-Order (ATO). Drives MRP II planning logic and order type selection.. Valid values are `MTO|MTS|ETO|ATO`',
    `receiving_storage_location` STRING COMMENT 'The SAP storage location (LGORT) to which the finished goods produced under this version are received upon goods receipt. Supports inventory management and warehouse operations.. Valid values are `^[A-Z0-9]{1,4}$`',
    `repetitive_manufacturing_allowed` BOOLEAN COMMENT 'Indicates whether this production version is enabled for repetitive manufacturing (SAP MKAL.SERKZ). When true, rate-based planning and backflushing are applicable. Relevant for high-volume, continuous production scenarios.. Valid values are `true|false`',
    `routing_type` STRING COMMENT 'The type of task list (PLNTY) associated with this production version. routing is standard discrete manufacturing; rate_routing is used for repetitive manufacturing; master_recipe is used for process manufacturing.. Valid values are `routing|rate_routing|reference_operation_set|master_recipe`',
    `scheduling_type` STRING COMMENT 'The scheduling direction used when calculating production dates for orders using this version: forward (from start date), backward (from required finish date), or current_date. Drives lead time calculation in MRP II.. Valid values are `forward|backward|current_date`',
    `status` STRING COMMENT 'Current operational status of the production version. active means it is available for MRP II planning and shop floor execution. inactive means it is defined but not currently used. locked means it is frozen for change control. obsolete means it has been superseded.. Valid values are `active|inactive|locked|under_review|obsolete`',
    `valid_from_date` DATE COMMENT 'The date from which this production version is valid and can be used for MRP II planning and production order creation (SAP MKAL.ADATU). Defines the start of the validity period.. Valid values are `^d{4}-d{2}-d{2}$`',
    `valid_to_date` DATE COMMENT 'The date until which this production version is valid (SAP MKAL.BDATU). After this date, the version is no longer proposed by MRP II for new production orders. Supports time-phased manufacturing method transitions.. Valid values are `^d{4}-d{2}-d{2}$`',
    CONSTRAINT pk_version PRIMARY KEY(`version_id`)
) COMMENT 'Production version master data defining the valid combination of BOM and routing for manufacturing a specific material at a specific plant (SAP PP Production Version). Stores material number, plant, production version code, description, valid-from/valid-to dates, BOM alternative, routing group/counter, lot size range (minimum/maximum), production line, and status (active, inactive). Enables multiple manufacturing methods for the same product and drives MRP II planning with the correct BOM/routing combination.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`batch` (
    `batch_id` BIGINT COMMENT 'Unique surrogate identifier for the batch master record in the Databricks Silver Layer. Serves as the primary key for all batch-level traceability and genealogy operations.',
    `goods_receipt_id` BIGINT COMMENT 'Foreign key linking to procurement.goods_receipt. Business justification: In process manufacturing, production batches of raw materials are created at goods receipt. Traceability regulations require linking the production batch directly to the goods receipt for full upstrea',
    `lifecycle_id` BIGINT COMMENT 'Foreign key linking to product.product_lifecycle. Business justification: Batches track which product lifecycle phase was active during manufacturing. This supports obsolescence management, warranty tracking, and determining which production standards/specifications were ap',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: A production batch directly corresponds to an inventory lot/batch record created upon goods receipt or production output. Pharmaceutical and discrete manufacturing require this link for end-to-end bat',
    `material_specification_id` BIGINT COMMENT 'Foreign key linking to engineering.material_specification. Business justification: Each production batch must be traceable to the engineering material specification it was produced against. Used in batch records, certificates of conformance, and regulatory traceability audits in ind',
    `order_confirmation_id` BIGINT COMMENT 'Foreign key linking to order.order_confirmation. Business justification: Production batches are created and traceable to specific confirmed customer orders, especially in make-to-order manufacturing. Quality and traceability teams link batches to order confirmations for en',
    `certificate_of_analysis_number` STRING COMMENT 'Reference number of the Certificate of Analysis (CoA) document associated with this batch. The CoA documents the actual test results and quality characteristics confirming the batch meets specification. Linked to SAP DMS or external document management.. Valid values are `^[A-Z0-9-.]{1,30}$`',
    `changed_by_user` STRING COMMENT 'SAP user ID (AENAM) of the person who last modified the batch master record. Supports change management audit trails and accountability in quality-regulated environments.. Valid values are `^[A-Z0-9_-.]{1,12}$`',
    `classification_class_number` STRING COMMENT 'SAP classification class number (KLASSE) assigned to this batch for batch classification. Defines the set of characteristics (e.g., purity, viscosity, tensile strength) used to describe and search for batches.. Valid values are `^[A-Z0-9_]{1,18}$`',
    `classification_values` STRING COMMENT 'Serialized JSON string containing all batch classification characteristic values from SAP Classification System (AUSP) that do not have dedicated columns (e.g., color, hardness, moisture content, particle size). Enables flexible storage of material-specific quality parameters without schema changes.',
    `country_of_origin_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code indicating the country where the batch material was manufactured or substantially transformed. Required for customs declarations, trade compliance, and preferential origin determination.. Valid values are `^[A-Z]{3}$`',
    `created_by_user` STRING COMMENT 'SAP user ID (ERNAM) of the person who created the batch master record. Required for audit trail and accountability in regulated manufacturing environments.. Valid values are `^[A-Z0-9_-.]{1,12}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the batch master record was first created in the source system (SAP MCHA-ERSDA + MCHA-CRTM). Used for audit trail, data lineage, and batch lifecycle tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `goods_receipt_date` DATE COMMENT 'Date on which the batch was received into inventory via goods receipt posting (SAP MSEG-BUDAT). For externally procured batches, this is the inbound logistics date used for aging, FIFO, and supplier lead time analysis.. Valid values are `^d{4}-d{2}-d{2}$`',
    `goods_receipt_number` STRING COMMENT 'SAP material document number (MBLNR) for the goods receipt posting that created or received this batch. Provides the inbound logistics and inventory posting reference for traceability.. Valid values are `^[0-9]{1,10}$`',
    `hazardous_material_flag` BOOLEAN COMMENT 'Indicates whether the batch contains hazardous materials requiring special handling, storage, labeling, and transport documentation (e.g., SDS, UN number). Drives HSE compliance workflows and warehouse segregation rules.. Valid values are `true|false`',
    `inspection_lot_number` STRING COMMENT 'SAP QM inspection lot number (PRUEFLOS) linked to this batch for quality inspection. Connects the batch to the inspection results, usage decision, and defect records in the Quality Management module.. Valid values are `^[0-9]{1,12}$`',
    `is_restricted_substance_compliant` BOOLEAN COMMENT 'Indicates whether this batch has been verified as compliant with restricted substance regulations including EU RoHS (Restriction of Hazardous Substances) and REACH (Registration, Evaluation, Authorisation and Restriction of Chemicals). Required for CE marking and export compliance.. Valid values are `true|false`',
    `last_changed_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent change to the batch master record in the source system (SAP MCHA-LAEDA + MCHA-LAEZT). Supports change detection, delta loading, and audit compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `manufacturing_date` DATE COMMENT 'The date on which the batch was manufactured or produced (SAP MCHA-HSDAT). Used for shelf life calculation, FIFO/FEFO inventory management, and regulatory compliance documentation.. Valid values are `^d{4}-d{2}-d{2}$`',
    `material_description` STRING COMMENT 'Short text description of the material associated with this batch, sourced from the SAP material master (MAKT-MAKTX). Supports human-readable identification in reports and quality documents.',
    `material_number` STRING COMMENT 'SAP material number (MATNR) of the material to which this batch belongs. Identifies the specific product or raw material managed in lot/batch control.. Valid values are `^[A-Z0-9-]{1,40}$`',
    `ncr_number` STRING COMMENT 'Reference to the Non-Conformance Report (NCR) raised against this batch if quality defects or deviations were identified. Links the batch to the CAPA process and corrective action tracking in the QMS.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `next_inspection_date` DATE COMMENT 'Scheduled date for the next periodic quality inspection of this batch. Supports recurring inspection planning for long-shelf-life or regulated materials and triggers QM inspection lot creation.. Valid values are `^d{4}-d{2}-d{2}$`',
    `origin_type` STRING COMMENT 'Indicates whether the batch was created through internal manufacturing (production order), external procurement (purchase order/GRN), subcontracting, or customer returns. Drives traceability and genealogy logic.. Valid values are `internal_production|external_procurement|subcontracting|returns`',
    `plant_code` STRING COMMENT 'SAP plant code (WERKS) where the batch was produced or received. Determines the organizational unit responsible for batch management, quality inspection, and inventory valuation.. Valid values are `^[A-Z0-9]{1,4}$`',
    `production_order_number` STRING COMMENT 'SAP production order number (AUFNR) that created this batch. Links the batch to the manufacturing execution context including routing, work center, BOM, and planned/actual quantities. Applicable for internally produced batches.. Valid values are `^[0-9]{1,12}$`',
    `purity_percent` DECIMAL(18,2) COMMENT 'Purity level of the batch expressed as a percentage, stored as a batch classification characteristic value. Critical quality parameter for chemical, pharmaceutical, and specialty material batches used in acceptance/rejection decisions.. Valid values are `^(100(.0{1,4})?|[0-9]{1,2}(.[0-9]{1,4})?)$`',
    `quantity` DECIMAL(18,2) COMMENT 'Total quantity of material in this batch at the time of creation or last stock posting (SAP MCHB-CLABS + CEINM + CSPEM + CEINM). Represents the lot size for production planning, quality sampling, and inventory management.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `reach_svhc_flag` BOOLEAN COMMENT 'Indicates whether this batch contains any Substance of Very High Concern (SVHC) as defined under EU REACH regulation. Triggers mandatory disclosure obligations to customers and downstream users when SVHC concentration exceeds 0.1% w/w.. Valid values are `true|false`',
    `remaining_shelf_life_days` STRING COMMENT 'Number of days remaining before the batch expires, calculated as the difference between expiry date and the current date. Used for FEFO prioritization, near-expiry alerts, and inventory disposition decisions.. Valid values are `^[0-9]{1,5}$`',
    `retest_date` DATE COMMENT 'Date by which the batch must be retested to confirm it still meets quality specifications (SAP MCHA-RRDAT). Used for periodic quality re-evaluation of long shelf-life materials and regulatory compliance.. Valid values are `^d{4}-d{2}-d{2}$`',
    `shelf_life_days` STRING COMMENT 'Total shelf life of the batch expressed in days, as defined in the material master shelf life data (SAP MRP4 view - MHDRZ). Used to calculate expiry date and manage FEFO-based inventory consumption.. Valid values are `^[0-9]{1,5}$`',
    `status` STRING COMMENT 'Current stock/quality status of the batch as managed in SAP MM/QM (MCHB-EINME / Batch Classification). Determines whether the batch is available for use: unrestricted (available), quality_inspection (under QM hold), blocked (not available), restricted (conditionally available), or obsolete (expired/decommissioned).. Valid values are `unrestricted|quality_inspection|blocked|restricted|obsolete`',
    `storage_location_code` STRING COMMENT 'SAP storage location code (LGORT) where the batch is physically stored within the plant. Used for inventory management, warehouse operations, and stock transfer processes.. Valid values are `^[A-Z0-9]{1,4}$`',
    `supplier_batch_number` STRING COMMENT 'The batch or lot number assigned by the external supplier for procured materials (SAP LICHA). Required for supplier traceability, incoming quality inspection, and regulatory compliance (e.g., REACH, RoHS).. Valid values are `^[A-Z0-9-.]{1,30}$`',
    `supplier_number` STRING COMMENT 'SAP vendor/supplier number (LIFNR) for externally procured batches. Enables supplier quality tracking, incoming inspection correlation, and supplier performance analytics.. Valid values are `^[0-9]{1,10}$`',
    `tensile_strength_mpa` DECIMAL(18,2) COMMENT 'Tensile strength of the batch material in megapascals (MPa), stored as a batch classification characteristic. Critical mechanical property for metal, composite, and structural material batches used in quality release decisions.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `unit_of_measure` STRING COMMENT 'Base unit of measure for the batch quantity (SAP MEINH/MEINS), such as KG, L, EA, M, M2, M3. Aligns with SAP material master base UoM for consistent inventory and quality reporting.. Valid values are `^[A-Z]{1,6}$`',
    `usage_decision_code` STRING COMMENT 'SAP QM usage decision code (ENTSCHEIDUNG) for the inspection lot associated with this batch. Determines the quality disposition: accept (unrestricted use), reject (block/scrap), or conditional release. Drives automatic batch status change.. Valid values are `^[A-Z0-9]{1,4}$`',
    `viscosity_mpa_s` DECIMAL(18,2) COMMENT 'Viscosity measurement of the batch in millipascal-seconds (mPa·s), stored as a batch classification characteristic. Key quality parameter for fluid, adhesive, coating, and polymer material batches.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    CONSTRAINT pk_batch PRIMARY KEY(`batch_id`)
) COMMENT 'Batch master record for lot-controlled materials produced or consumed in manufacturing (SAP MM/PP Batch Master). Stores batch number, material number, plant, storage location, batch status (unrestricted, quality inspection, blocked, restricted), manufacturing date, expiry date, shelf life, batch classification values (e.g., purity, viscosity, tensile strength), batch origin (internal production vs. external procurement), and certificate of analysis reference. SSOT for batch traceability and genealogy across the production and quality domains.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`batch_genealogy` (
    `batch_genealogy_id` BIGINT COMMENT 'Unique surrogate identifier for each batch genealogy relationship record in the Silver layer lakehouse. Serves as the primary key for the batch_genealogy data product.',
    `batch_id` BIGINT COMMENT 'Foreign key linking to production.batch. Business justification: batch_genealogy tracks the parent batch consumed during manufacturing. The FK parent_batch_id normalizes the parent_batch_number string reference and enables joins to batch master data for upstream tr',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.po_line_item. Business justification: Batch genealogy must trace input materials back to the specific PO line item that sourced them. Regulatory compliance and recall management in industrial manufacturing require this upstream traceabili',
    `routing_operation_id` BIGINT COMMENT 'Foreign key linking to production.routing_operation. Business justification: batch_genealogy records the operation step at which batch transformation occurred. The FK routing_operation_id enables joins to routing_operation master data for process-level genealogy traceability a',
    `work_center_id` BIGINT COMMENT 'Foreign key linking to production.work_center. Business justification: batch_genealogy.work_center_code (STRING) is a denormalized reference to the work_center master. Batch genealogy records capture the work center at which the parent-child batch transformation occurred',
    `child_batch_expiry_date` DATE COMMENT 'Shelf life expiration date of the child (produced) batch as recorded in SAP batch master. Used for finished product shelf life management, customer delivery compliance, and regulatory traceability.',
    `child_batch_number` STRING COMMENT 'Identifier of the child batch — the output material, assembly, or finished product batch that was produced or resulted from the manufacturing operation. In SAP PP, this corresponds to the To Batch in the batch where-used list.',
    `child_batch_status` STRING COMMENT 'Quality/inventory status of the child (produced) batch at the time of production confirmation, as recorded in SAP QM. Indicates whether the produced batch passed quality inspection or requires further disposition.. Valid values are `unrestricted|quality_inspection|blocked|restricted|in_transit|scrapped`',
    `child_material_description` STRING COMMENT 'Human-readable description of the child batch material, denormalized for traceability reports, recall notifications, and regulatory submissions.',
    `child_material_number` STRING COMMENT 'SAP material number (or equivalent ERP identifier) of the child batch material. Enables cross-referencing to the material master for finished product specifications and compliance data.',
    `consumed_quantity` DECIMAL(18,2) COMMENT 'Actual quantity of the parent batch that was consumed during the manufacturing operation. Used for material balance calculations, yield analysis, and traceability completeness verification.',
    `consumed_quantity_uom` STRING COMMENT 'Unit of measure for the consumed quantity of the parent batch (e.g., KG, L, EA). Aligned with SAP base unit of measure for the parent material.. Valid values are `KG|G|L|ML|EA|M|M2|M3|LB|OZ|GAL|TON|PC`',
    `country_of_manufacture_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country where the batch transformation occurred. Required for customs declarations, CE marking, RoHS/REACH compliance, and country-of-origin traceability in global supply chains.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the batch genealogy record was first created in the source system of record (SAP PP or Siemens Opcenter MES). Used for audit trail, data lineage, and regulatory record retention compliance.',
    `genealogy_record_number` STRING COMMENT 'Business-facing unique identifier for the batch genealogy relationship record, used in quality investigations, recall management, and regulatory submissions. Typically sourced from SAP PP Batch Where-Used or Siemens Opcenter MES.. Valid values are `^BG-[0-9]{4}-[0-9]{8}$`',
    `goods_movement_document_number` STRING COMMENT 'SAP material document number (from MIGO/MB1A) recording the goods issue of the parent batch or goods receipt of the child batch. Provides the financial and inventory audit trail for the batch relationship.',
    `inspection_lot_number` STRING COMMENT 'SAP QM inspection lot number associated with the child batch produced in this genealogy record. Links the batch genealogy to quality inspection results, usage decisions, and non-conformance reports (NCR).',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent update to the batch genealogy record in the source system. Supports change detection, incremental data loading in the Silver layer, and audit trail completeness.',
    `merge_sequence_number` STRING COMMENT 'Sequential number identifying the order of parent batches when multiple parent batches are merged into a single child batch (relationship_type = merge). Enables reconstruction of the full merge genealogy and proportional quantity attribution.',
    `ncr_number` STRING COMMENT 'Reference to the Non-Conformance Report (NCR) raised against the parent or child batch in this genealogy record. Enables direct linkage between batch traceability and quality defect management for CAPA investigations.',
    `operation_end_timestamp` TIMESTAMP COMMENT 'Actual end date and time of the manufacturing operation during which the batch relationship was established. Together with operation_start_timestamp, defines the production time window for traceability and cycle time analysis.',
    `operation_number` STRING COMMENT 'Routing operation number (e.g., 0010, 0020) within the production order at which the batch relationship was established — i.e., where the parent batch was consumed and the child batch was produced or transformed.. Valid values are `^[0-9]{4}$`',
    `operation_start_timestamp` TIMESTAMP COMMENT 'Actual start date and time of the manufacturing operation during which the batch relationship was established. Used for time-based traceability, shift analysis, and process timeline reconstruction during quality investigations.',
    `parent_batch_expiry_date` DATE COMMENT 'Shelf life expiration date of the parent batch as recorded in SAP batch master. Critical for FEFO (First Expired First Out) compliance, regulatory submissions, and determining if expired materials were used in production.',
    `parent_batch_status` STRING COMMENT 'Quality/inventory status of the parent batch at the time of consumption, as recorded in SAP QM batch status management. Indicates whether the consumed batch was in unrestricted use, under quality inspection, or blocked — critical for quality investigations.. Valid values are `unrestricted|quality_inspection|blocked|restricted|in_transit|scrapped`',
    `parent_material_description` STRING COMMENT 'Human-readable description of the parent batch material, denormalized for reporting and traceability documents without requiring a join to the material master.',
    `parent_material_number` STRING COMMENT 'SAP material number (or equivalent ERP identifier) of the parent batch material. Enables cross-referencing to the material master for specification, classification, and compliance data.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility where the batch genealogy relationship was established. Supports multi-plant traceability and regional regulatory compliance reporting.. Valid values are `^[A-Z0-9]{4}$`',
    `produced_quantity` DECIMAL(18,2) COMMENT 'Actual quantity of the child batch that was produced or resulted from the manufacturing operation. Used for yield calculations, material balance, and production confirmation reporting.',
    `produced_quantity_uom` STRING COMMENT 'Unit of measure for the produced quantity of the child batch (e.g., KG, EA, L). Aligned with SAP base unit of measure for the child material.. Valid values are `KG|G|L|ML|EA|M|M2|M3|LB|OZ|GAL|TON|PC`',
    `production_order_number` STRING COMMENT 'Reference to the SAP PP production order or MES work order under which the parent-child batch relationship was created. Links genealogy records to the manufacturing execution context.',
    `recall_flag` BOOLEAN COMMENT 'Indicates whether this batch genealogy record has been flagged as part of an active product recall or field action. When true, the record is included in recall scope reports and regulatory notifications. Critical for recall management and regulatory compliance.. Valid values are `true|false`',
    `recall_reference_number` STRING COMMENT 'Reference number of the product recall or field action campaign to which this batch genealogy record belongs. Populated when recall_flag is true. Enables aggregation of all affected batches under a single recall event.',
    `record_status` STRING COMMENT 'Lifecycle status of the batch genealogy record. active indicates a valid, confirmed relationship; reversed indicates the goods movement was reversed in SAP; cancelled indicates the production order was cancelled; superseded indicates the record was replaced by a corrected entry.. Valid values are `active|reversed|cancelled|superseded`',
    `regulatory_compliance_standard` STRING COMMENT 'Primary regulatory or quality standard under which this batch genealogy record must be maintained and reported. Drives retention period, traceability depth, and reporting format requirements. Multiple standards may apply; the most stringent is recorded.. Valid values are `ISO_9001|IATF_16949|FDA_21CFR|EU_GMP|RoHS|REACH|CE|UL|AS9100|NONE`',
    `relationship_type` STRING COMMENT 'Classifies the nature of the parent-child batch relationship. component_to_assembly is the standard BOM consumption; split occurs when one batch is divided into multiple child batches; merge when multiple parent batches are combined; rework when a non-conforming batch is reprocessed; co_product and by_product for simultaneous production outputs; reprocess for quality-driven reprocessing.. Valid values are `component_to_assembly|rework|split|merge|co_product|by_product|reprocess`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this batch genealogy record was sourced (e.g., SAP PP Batch Where-Used, Siemens Opcenter MES). Supports data lineage, audit trail, and Silver layer reconciliation.. Valid values are `SAP_PP|OPCENTER_MES|TEAMCENTER_PLM|MANUAL|OTHER`',
    `split_sequence_number` STRING COMMENT 'Sequential number identifying the order of child batches when a parent batch is split into multiple child batches (relationship_type = split). Enables reconstruction of the full split genealogy tree and quantity reconciliation.',
    `storage_location_code` STRING COMMENT 'SAP storage location from which the parent batch was issued or to which the child batch was received. Supports inventory traceability and warehouse management integration.',
    `traceability_direction` STRING COMMENT 'Indicates the direction of traceability this record supports. forward traces from raw material/component to finished product (where-used); backward traces from finished product to raw material/component (where-from); bidirectional supports both directions. Critical for product recall scope determination.. Valid values are `forward|backward|bidirectional`',
    `traceability_timestamp` TIMESTAMP COMMENT 'The precise date and time at which the batch genealogy relationship was recorded in the system of record (SAP PP or Siemens Opcenter MES). This is the authoritative timestamp for regulatory traceability and recall scope determination.',
    `yield_rate_percent` DECIMAL(18,2) COMMENT 'Ratio of produced quantity to consumed quantity expressed as a percentage, representing the material conversion efficiency for this specific batch relationship. Supports yield analysis and process capability monitoring (SPC).. Valid values are `^(100(.0{1,4})?|[0-9]{1,2}(.[0-9]{1,4})?)$`',
    CONSTRAINT pk_batch_genealogy PRIMARY KEY(`batch_genealogy_id`)
) COMMENT 'Tracks parent-child relationships between batches consumed and produced during manufacturing operations, enabling full forward and backward batch traceability (SAP PP Batch Where-Used / Batch Genealogy). Stores parent batch reference, child batch reference, production order reference, operation reference, consumed quantity, produced quantity, relationship type (component-to-assembly, rework, split, merge), and traceability timestamp. Critical for product recall management, quality investigations, and regulatory compliance (ISO 9001, FDA, automotive IATF 16949).';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`downtime_event` (
    `downtime_event_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying each downtime event record in the silver layer lakehouse. Serves as the primary key for all downstream joins and OEE/TPM calculations.',
    `asset_notification_id` BIGINT COMMENT 'Foreign key linking to asset.asset_notification. Business justification: When a machine goes down on the shop floor, an asset notification is raised immediately. Production supervisors link downtime events to notifications to trigger maintenance response and track resoluti',
    `cost_allocation_id` BIGINT COMMENT 'Foreign key linking to finance.cost_allocation. Business justification: Unplanned downtime incurs idle capacity costs that must be allocated to cost centers or orders. Finance uses this link to distribute machine downtime costs across cost objects during period-end cost a',
    `failure_record_id` BIGINT COMMENT 'Foreign key linking to asset.failure_record. Business justification: Production downtime caused by equipment failures must reference the formal failure record for root cause analysis, warranty claims, and reliability engineering. Links operational impact to technical f',
    `location_id` BIGINT COMMENT 'Foreign key linking to logistics.location. Business justification: Downtime events are tied to a physical location on the shop floor or facility. Maintenance and operations managers use this to correlate downtime with logistics disruptions (e.g., blocked aisles, dela',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Unplanned downtime events often require emergency spare part procurement. Maintenance and production teams link the downtime event to the resulting purchase order to track response time, cost of downt',
    `shift_id` BIGINT COMMENT 'Foreign key linking to production.shift. Business justification: downtime_event occurs during a specific shift. The FK shift_id normalizes the shift_code reference and enables joins to shift master data for shift-level downtime analysis and MTTR/MTBF calculations.',
    `work_center_id` BIGINT COMMENT 'Foreign key linking to production.work_center. Business justification: downtime_event occurs at a specific work_center. The FK work_center_id enables joins to work_center master data for downtime analysis, MTTR/MTBF calculations, and OEE availability loss attribution per',
    `capa_reference` STRING COMMENT 'Reference number of the formal CAPA record raised as a result of this downtime event. Links to the QMS CAPA module for systemic root cause elimination and recurrence prevention tracking.',
    `category` STRING COMMENT 'High-level classification of the downtime event type. Drives OEE loss categorization (availability loss vs. planned stops), TPM pillar analysis, and MTBF/MTTR segmentation. Aligns with Opcenter MES downtime category taxonomy.. Valid values are `breakdown|planned_maintenance|changeover|material_shortage|quality_hold|operator_absence|scheduled_downtime|trial_run|no_demand|other`',
    `corrective_action` STRING COMMENT 'Description of the immediate corrective action taken to restore production (e.g., replaced bearing, reset PLC, cleared material jam). Distinct from CAPA — this is the immediate fix, not the systemic preventive action.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant or facility where the downtime event occurred. Supports multi-country OEE benchmarking, regulatory reporting, and regional maintenance performance analysis.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the downtime event record was first created in the source system. Used for audit trail, data freshness monitoring, and SLA compliance on downtime reporting timeliness.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `detection_method` STRING COMMENT 'Method by which the downtime event was detected and initiated. Distinguishes between human-reported events and automated detection via SCADA, PLC fault codes, or MindSphere predictive alerts. Supports IIoT maturity assessment.. Valid values are `operator_reported|automated_sensor|scada_alarm|plc_fault|mes_alert|visual_inspection|predictive_alert|other`',
    `duration_minutes` DECIMAL(18,2) COMMENT 'Total elapsed duration of the downtime event in minutes, calculated from start and end timestamps. Stored explicitly to support direct aggregation in OEE availability calculations and TPM dashboards without requiring timestamp arithmetic at query time.. Valid values are `^d+(.d{1,2})?$`',
    `end_timestamp` TIMESTAMP COMMENT 'Exact date and time when the downtime event was resolved and production resumed. Used with start_timestamp to compute duration and MTTR. Null if the event is still open.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `event_number` STRING COMMENT 'Human-readable business identifier for the downtime event, typically generated by Siemens Opcenter MES or SAP PM. Used for cross-system referencing, shop floor communication, and audit trails.. Valid values are `^DT-[0-9]{4}-[0-9]{6}$`',
    `failure_mode` STRING COMMENT 'Specific failure mode description identifying how the equipment or process failed, aligned with FMEA/PFMEA failure mode taxonomy. Supports root cause analysis and reliability engineering programs.',
    `fault_code` STRING COMMENT 'Fault or alarm code generated by the PLC, SCADA, or DCS system at the time of the downtime event. Provides precise machine-level diagnostic information for maintenance engineers and reliability analysis.',
    `is_planned` BOOLEAN COMMENT 'Indicates whether the downtime event was planned (e.g., scheduled maintenance, changeover, trial run) or unplanned (e.g., breakdown, quality hold). Critical for correctly computing OEE availability — only unplanned downtime reduces OEE availability.. Valid values are `true|false`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the downtime event record. Supports incremental data loading in the Databricks lakehouse pipeline and change data capture (CDC) processing.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `lost_production_quantity` DECIMAL(18,2) COMMENT 'Quantity of production units lost or not produced as a direct result of the downtime event. Feeds OEE performance and availability loss calculations, and supports financial impact assessment of downtime.. Valid values are `^d+(.d{1,4})?$`',
    `lost_production_uom` STRING COMMENT 'Unit of measure for the lost production quantity (e.g., EA for each, KG for kilograms, M for meters). Ensures dimensional consistency when aggregating lost production across different product types.. Valid values are `EA|KG|L|M|M2|M3|PC|SET|TON`',
    `machine_code` STRING COMMENT 'Unique identifier of the specific machine or equipment asset within the work center that experienced the downtime. Corresponds to the equipment number in SAP PM and Maximo EAM.',
    `machine_name` STRING COMMENT 'Descriptive name of the machine or equipment asset that experienced the downtime. Supports readability in OEE dashboards and TPM reports.',
    `maintenance_work_order_number` STRING COMMENT 'Reference to the SAP PM or Maximo EAM maintenance work order created to address the downtime event. Links downtime records to maintenance execution, spare parts consumption, and labor cost tracking.',
    `mes_event_code` STRING COMMENT 'Native event identifier from Siemens Opcenter MES downtime module. Enables traceability back to the source system record for reconciliation and audit purposes.',
    `mindsphere_asset_code` STRING COMMENT 'Asset identifier from Siemens MindSphere IIoT platform used to correlate the downtime event with real-time telemetry, predictive alerts, and condition monitoring data from the affected machine or work center.',
    `oee_impact_category` STRING COMMENT 'Classification of how this downtime event impacts the OEE calculation — specifically which OEE loss category it belongs to (availability loss for unplanned stops, planned stop for scheduled downtime). Enables automated OEE waterfall chart generation.. Valid values are `availability_loss|performance_loss|quality_loss|planned_stop|no_impact`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility where the downtime event occurred. Enables multi-plant OEE benchmarking and global downtime analysis across the multinational enterprise.. Valid values are `^[A-Z0-9]{4}$`',
    `production_order_number` STRING COMMENT 'SAP production order number that was active or impacted at the time of the downtime event. Links the downtime to the specific manufacturing order for cost impact and schedule deviation analysis.',
    `reason_code` STRING COMMENT 'Standardized reason code from the MES or ERP downtime reason catalog that identifies the specific cause of the downtime event (e.g., mechanical failure, electrical fault, tooling wear). Enables Pareto analysis and FMEA correlation.',
    `reason_description` STRING COMMENT 'Human-readable description of the downtime reason code. Provides context for operators and maintenance engineers when reviewing downtime records without requiring a lookup to the reason code catalog.',
    `reported_by` STRING COMMENT 'Employee ID or username of the operator or technician who reported or initiated the downtime event record in the MES or maintenance system. Supports accountability tracking and operator performance analysis.',
    `resolved_by` STRING COMMENT 'Employee ID or username of the maintenance technician or engineer who resolved the downtime event. Used for MTTR analysis by technician, skills gap identification, and TPM workforce planning.',
    `responsible_department` STRING COMMENT 'Department accountable for resolving or owning the downtime event (e.g., Maintenance, Production, Quality, Logistics). Used for departmental KPI reporting and escalation routing.',
    `root_cause` STRING COMMENT 'Identified root cause of the downtime event as determined through investigation (e.g., 5-Why analysis, fishbone diagram). Populated after CAPA investigation is completed. Supports TPM and continuous improvement programs.',
    `shift_code` STRING COMMENT 'Production shift identifier during which the downtime event occurred (e.g., A-shift, B-shift, night shift). Enables shift-level downtime analysis and supports labor accountability in TPM programs.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which the downtime event was originated or ingested (e.g., Siemens Opcenter MES, MindSphere IIoT, SAP PM, Maximo EAM). Supports data lineage and reconciliation in the lakehouse.. Valid values are `opcenter_mes|mindsphere|sap_pm|maximo|manual|other`',
    `start_timestamp` TIMESTAMP COMMENT 'Exact date and time when the downtime event began, as recorded by Opcenter MES or MindSphere IIoT. Critical for MTBF calculations, OEE availability component, and shift-level downtime reporting.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `status` STRING COMMENT 'Current lifecycle status of the downtime event record. Drives workflow routing in MES and maintenance systems — open events trigger alerts, resolved events enable MTTR calculation, closed events are locked for reporting.. Valid values are `open|in_progress|resolved|closed|cancelled`',
    `work_center_code` STRING COMMENT 'Code identifying the work center or production cell where the downtime event occurred. Aligns with SAP PP/PM work center master data and Opcenter MES resource definitions.',
    CONSTRAINT pk_downtime_event PRIMARY KEY(`downtime_event_id`)
) COMMENT 'Detailed record of unplanned and planned downtime events on the shop floor (Opcenter MES Downtime / MindSphere Asset Downtime). Stores work center/machine, downtime start/end timestamp, total duration (minutes), downtime category (breakdown, planned maintenance, changeover, material shortage, quality hold, operator absence), downtime reason code, responsible department, production order impacted, lost production quantity, and corrective action taken. Feeds TPM programs, MTBF/MTTR calculations, and OEE availability component. Distinct from OEE events in that it captures the full downtime record with root cause.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`shift` (
    `shift_id` BIGINT COMMENT 'Unique surrogate identifier for each production shift definition record in the Silver Layer lakehouse. Serves as the primary key for all downstream joins and OEE calculations.',
    `break_duration_minutes` STRING COMMENT 'Total scheduled break time in minutes for the shift (sum of all meal breaks, rest breaks, and paid/unpaid breaks). Subtracted from gross duration to derive net available production time.. Valid values are `^d{1,3}$`',
    `break_schedule_details` STRING COMMENT 'Structured text description of the break schedule within the shift, specifying break start times and durations (e.g., 10:00-10:15 rest; 12:00-12:30 meal; 15:00-15:15 rest). Stored as a formatted string for display in MES and scheduling tools.',
    `code` STRING COMMENT 'Short alphanumeric business code uniquely identifying the shift definition within a plant (e.g., SH-DAY, SH-NIGHT, SH-SWING). Used as the natural key in MES and ERP integrations.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant location where this shift is defined (e.g., USA, DEU, CHN). Enables country-specific labor law compliance, regulatory reporting, and multi-regional OEE benchmarking.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this shift definition record was first created in the source system or Silver Layer, in ISO 8601 format with timezone offset. Used for audit trail and data lineage.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `crosses_midnight` BOOLEAN COMMENT 'Indicates whether the shift spans across midnight (i.e., end_time is earlier than start_time on the clock). Critical for correct date assignment of production orders and OEE period calculations for night shifts.. Valid values are `true|false`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to financial attributes of this shift record (e.g., USD, EUR, CNY). Supports multi-currency reporting in multinational manufacturing operations.. Valid values are `^[A-Z]{3}$`',
    `description` STRING COMMENT 'Detailed narrative description of the shift, including its purpose, applicable production lines, or special operational notes (e.g., reduced-capacity weekend shift, holiday skeleton crew).',
    `duration_hours` DECIMAL(18,2) COMMENT 'Total gross duration of the shift in decimal hours (e.g., 8.00, 10.00, 12.00). Represents the full clock time from start to end before deducting breaks. Used as the denominator in OEE availability calculations.. Valid values are `^d{1,3}(.d{1,2})?$`',
    `effective_from_date` DATE COMMENT 'The calendar date from which this shift definition becomes valid and applicable for production scheduling. Supports time-variant shift configurations for seasonal or contractual changes.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effective_to_date` DATE COMMENT 'The calendar date on which this shift definition expires and is no longer valid for production scheduling. A null value indicates the shift is open-ended with no planned expiry.. Valid values are `^d{4}-d{2}-d{2}$`',
    `end_time` STRING COMMENT 'Scheduled end time of the shift in HH:mm:ss 24-hour format (e.g., 14:00:00 for Day Shift). Combined with start_time to determine the gross shift window for capacity and OEE calculations.. Valid values are `^([01]d|2[0-3]):[0-5]d:[0-5]d$`',
    `friday_applicable` BOOLEAN COMMENT 'Indicates whether this shift definition is scheduled to operate on Fridays. Used in weekly production scheduling and MRP II capacity planning.. Valid values are `true|false`',
    `labor_agreement_code` STRING COMMENT 'Code referencing the collective bargaining agreement or labor contract governing this shifts working conditions, break entitlements, and overtime rules. Ensures compliance with labor regulations and union agreements.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this shift definition record in the source system or Silver Layer. Used for incremental data loading, change detection, and audit compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `monday_applicable` BOOLEAN COMMENT 'Indicates whether this shift definition is scheduled to operate on Mondays. Used in weekly production scheduling and MRP II capacity planning.. Valid values are `true|false`',
    `name` STRING COMMENT 'Human-readable name of the production shift (e.g., Day Shift, Night Shift, Swing Shift, Morning Shift, Afternoon Shift). Used in scheduling boards, OEE dashboards, and production reports.',
    `net_available_time_hours` DECIMAL(18,2) COMMENT 'Planned available production time in decimal hours after deducting all scheduled breaks and planned downtime from the gross shift duration. This is the planned operating time used as the basis for OEE availability rate calculations per ISO 22400-2.. Valid values are `^d{1,3}(.d{1,2})?$`',
    `number_of_breaks` STRING COMMENT 'Count of distinct scheduled break periods within the shift (e.g., 1 meal break + 2 rest breaks = 3). Used in MES break scheduling and shop floor Andon system configuration.. Valid values are `^d{1,2}$`',
    `oee_target_percent` DECIMAL(18,2) COMMENT 'Target Overall Equipment Effectiveness (OEE) percentage for this shift, representing the planned benchmark for availability, performance, and quality combined. Used to evaluate actual shift OEE against the planned target in production analytics.. Valid values are `^(100(.0{1,2})?|d{1,2}(.d{1,2})?)$`',
    `overtime_eligible` BOOLEAN COMMENT 'Indicates whether production hours worked in this shift beyond the standard duration qualify for overtime compensation under the applicable labor agreement. Used in labor cost calculations and payroll integration.. Valid values are `true|false`',
    `pattern_code` STRING COMMENT 'Code referencing the shift rotation pattern or schedule group to which this shift belongs (e.g., 3-SHIFT-ROTATING, 2-SHIFT-FIXED, CONTINENTAL). Links individual shift definitions to their broader scheduling pattern for MRP II capacity planning.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility to which this shift definition belongs. Enables multi-plant OEE segmentation and shift-based capacity planning.. Valid values are `^[A-Z0-9]{2,10}$`',
    `premium_pay_rate_percent` DECIMAL(18,2) COMMENT 'Percentage premium applied to the base labor rate for hours worked in this shift (e.g., 25% night shift premium, 50% weekend premium). Used in production cost calculations and COGS reporting.. Valid values are `^(100(.0{1,2})?|d{1,2}(.d{1,2})?)$`',
    `production_strategy` STRING COMMENT 'Manufacturing production strategy applicable to this shift (Make to Order, Make to Stock, Engineer to Order, Assemble to Order, or mixed). Determines how production orders are assigned and prioritized within the shift window.. Valid values are `MTO|MTS|ETO|ATO|mixed`',
    `saturday_applicable` BOOLEAN COMMENT 'Indicates whether this shift definition is scheduled to operate on Saturdays. Relevant for extended production weeks, overtime scheduling, and weekend capacity planning.. Valid values are `true|false`',
    `sequence_number` STRING COMMENT 'Ordinal position of the shift within a 24-hour production day cycle (e.g., 1 = first shift, 2 = second shift, 3 = third shift). Used to order shifts in scheduling boards and rotation pattern definitions.. Valid values are `^[1-9]d*$`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this shift definition was sourced (e.g., SAP_S4HANA, OPCENTER_MES). Supports data lineage tracking and reconciliation in the Silver Layer lakehouse.. Valid values are `SAP_S4HANA|OPCENTER_MES|MANUAL|LEGACY`',
    `start_time` STRING COMMENT 'Scheduled start time of the shift in HH:mm:ss 24-hour format (e.g., 06:00:00 for Day Shift). Used to calculate available production time and assign production orders to the correct shift window.. Valid values are `^([01]d|2[0-3]):[0-5]d:[0-5]d$`',
    `status` STRING COMMENT 'Current lifecycle status of the shift definition. Only active shifts are available for production order assignment and OEE calculations. Archived shifts are retained for historical reporting.. Valid values are `active|inactive|draft|archived`',
    `sunday_applicable` BOOLEAN COMMENT 'Indicates whether this shift definition is scheduled to operate on Sundays. Relevant for 24/7 continuous production environments and holiday/weekend capacity planning.. Valid values are `true|false`',
    `takt_time_seconds` DECIMAL(18,2) COMMENT 'Planned takt time in seconds for this shift, calculated as net available production time divided by customer demand rate. Represents the required production rhythm to meet demand within the shift window. Used in Lean Manufacturing and shop floor pacing.. Valid values are `^d+(.d{1,2})?$`',
    `thursday_applicable` BOOLEAN COMMENT 'Indicates whether this shift definition is scheduled to operate on Thursdays. Used in weekly production scheduling and MRP II capacity planning.. Valid values are `true|false`',
    `timezone` STRING COMMENT 'IANA timezone identifier for the plant location where this shift operates (e.g., America/New_York, Europe/Berlin, Asia/Shanghai). Critical for correct timestamp interpretation in global MES integrations and cross-plant OEE reporting.',
    `tuesday_applicable` BOOLEAN COMMENT 'Indicates whether this shift definition is scheduled to operate on Tuesdays. Used in weekly production scheduling and MRP II capacity planning.. Valid values are `true|false`',
    `type` STRING COMMENT 'Classification of the shift by its operational time window or purpose (e.g., day, night, swing, weekend, holiday, overtime). Used to segment OEE metrics and apply differential labor cost rates.. Valid values are `day|night|swing|morning|afternoon|weekend|holiday|overtime|skeleton`',
    `wednesday_applicable` BOOLEAN COMMENT 'Indicates whether this shift definition is scheduled to operate on Wednesdays. Used in weekly production scheduling and MRP II capacity planning.. Valid values are `true|false`',
    CONSTRAINT pk_shift PRIMARY KEY(`shift_id`)
) COMMENT 'Reference master for production shift definitions used in shop floor scheduling and OEE calculations. Stores shift code, shift name (e.g., Day Shift, Night Shift, Swing Shift), plant, shift start time, shift end time, shift duration (hours), break schedule, days of week applicability, and effective date range. Used to calculate available production time, assign production orders to shifts, and segment OEE metrics by shift. Distinct from workforce shift scheduling (owned by workforce domain) — this is the production-context shift reference.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`scrap_record` (
    `scrap_record_id` BIGINT COMMENT 'Unique surrogate identifier for each scrap record event in the production domain. Serves as the primary key for the scrap_record data product in the Databricks Silver layer.',
    `batch_id` BIGINT COMMENT 'Foreign key linking to production.batch. Business justification: scrap_record captures scrap generated from a specific batch. The FK batch_id normalizes the batch_number string reference and enables joins to batch master data for batch-level scrap analysis and yiel',
    `defect_code_id` BIGINT COMMENT 'Foreign key linking to quality.defect_code. Business justification: Production scrap must be categorized using standardized defect codes for Pareto analysis, trend reporting, and quality improvement initiatives. Used by production supervisors during scrap reporting.',
    `failure_record_id` BIGINT COMMENT 'Foreign key linking to asset.failure_record. Business justification: Scrap caused by equipment malfunction must be traceable to the specific failure record for warranty claims, quality investigations, and cost allocation. Quality engineers use this link daily in non-co',
    `lot_batch_id` BIGINT COMMENT 'Foreign key linking to inventory.lot_batch. Business justification: Scrap records must reference the specific inventory lot/batch being scrapped for full material traceability. Regulatory compliance and quality investigations require linking scrap events to the origin',
    `pfmea_id` BIGINT COMMENT 'Foreign key linking to engineering.pfmea. Business justification: Scrap events are classified against PFMEA failure modes so quality engineers can track actual vs. predicted failure rates. This closed-loop feedback between production scrap and process FMEA is standa',
    `production_order_cost_id` BIGINT COMMENT 'Foreign key linking to finance.production_order_cost. Business justification: Scrap events generate financial write-offs posted against the production order cost object. Cost accountants use this link to capture scrap variances and report waste costs against the manufacturing o',
    `returns_order_id` BIGINT COMMENT 'Foreign key linking to order.returns_order. Business justification: Scrap records generated during rework of customer returns are linked to the originating returns order. Quality and production teams use this link to track disposition of returned goods and calculate r',
    `routing_id` BIGINT COMMENT 'Foreign key linking to production.routing. Business justification: scrap_record references the routing under which scrap was generated. The FK routing_id enables joins to routing master data for process-level scrap analysis and routing optimization.',
    `routing_operation_id` BIGINT COMMENT 'Foreign key linking to production.routing_operation. Business justification: scrap_record captures scrap generated at a specific routing_operation step. The FK routing_operation_id enables joins to routing_operation master data for operation-level scrap analysis and process im',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Scrapped materials move to designated scrap storage locations. Material handlers need exact locations for segregation and disposal processing.',
    `shift_id` BIGINT COMMENT 'Foreign key linking to production.shift. Business justification: scrap_record captures scrap generated during a specific shift. The FK shift_id normalizes the shift_code reference and enables joins to shift master data for shift-level scrap analysis and quality tre',
    `shipment_item_id` BIGINT COMMENT 'Foreign key linking to logistics.shipment_item. Business justification: Scrap can originate from defective incoming shipment items. Quality and production teams trace scrap back to the specific shipment item to support supplier claims, incoming quality control, and root c',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to procurement.supplier. Business justification: Scrap caused by defective incoming materials is linked to the responsible supplier. Quality and procurement teams use this to raise supplier claims, update supplier performance scores, and drive corre',
    `work_center_id` BIGINT COMMENT 'Foreign key linking to production.work_center. Business justification: scrap_record captures scrap generated at a specific work_center. The FK work_center_id enables joins to work_center master data for scrap analysis, quality hotspot identification, and cost attribution',
    `capa_reference` STRING COMMENT 'Reference identifier of the Corrective and Preventive Action (CAPA) record initiated as a result of this scrap event. Enables traceability from scrap occurrence to quality improvement action.',
    `confirmation_number` STRING COMMENT 'Reference to the production confirmation document in SAP PP under which the scrap quantity was confirmed. Provides direct linkage to the goods movement and actual cost posting.',
    `cost_center_code` STRING COMMENT 'SAP controlling cost center to which the scrap cost is charged. Enables cost center-level scrap cost accountability and management reporting.',
    `cost_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the scrap cost amount (e.g., USD, EUR, CNY). Supports multi-currency financial consolidation for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the plant where the scrap event occurred. Supports multi-country regulatory compliance reporting (EPA, EU environmental directives) and regional scrap benchmarking.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the scrap record was created in the source system or ingested into the Silver layer. Supports audit trail, data lineage, and SLA compliance for data freshness.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `defect_code` STRING COMMENT 'Specific defect classification code from the quality defect catalog (SAP QM or Opcenter Quality) identifying the type of defect that caused the scrap. Supports SPC analysis and defect Pareto reporting.',
    `hazardous_material_flag` BOOLEAN COMMENT 'Indicates whether the scrapped material is classified as hazardous under applicable regulations (REACH, RoHS, EPA). Triggers mandatory hazardous waste disposal procedures and regulatory reporting obligations.. Valid values are `true|false`',
    `is_rework` BOOLEAN COMMENT 'Boolean flag indicating whether the scrapped item has been designated for rework rather than disposal. When true, a rework order reference should be present. Distinguishes reworkable non-conformances from permanent scrap for cost and yield analysis.. Valid values are `true|false`',
    `last_changed_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the scrap record in the source system. Used for incremental data loading, change detection, and audit trail maintenance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `material_description` STRING COMMENT 'Human-readable description of the scrapped material as maintained in the material master. Supports reporting and communication without requiring a material master lookup.',
    `material_number` STRING COMMENT 'SAP material number of the scrapped component or finished/semi-finished product. Used for material-level scrap rate analysis, COGS variance, and MRP II feedback.',
    `operation_number` STRING COMMENT 'Routing operation number at which the scrap was identified and reported. Enables pinpointing the specific manufacturing step responsible for the scrap event.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility where the scrap event occurred. Supports multi-plant scrap benchmarking and regional compliance reporting.',
    `posting_date` DATE COMMENT 'Accounting posting date for the scrap event in SAP, which may differ from the reporting timestamp. Determines the financial period in which the scrap cost is recognized for COGS variance and period-end closing.. Valid values are `^d{4}-d{2}-d{2}$`',
    `production_order_number` STRING COMMENT 'Reference to the production order under which the scrap event occurred. Links the scrap event to the originating manufacturing order for cost variance and OEE analysis.',
    `production_strategy` STRING COMMENT 'Manufacturing strategy under which the scrapped order was produced: Make to Order (MTO), Make to Stock (MTS), Engineer to Order (ETO), or Assemble to Order (ATO). Contextualizes scrap impact on customer commitments and inventory.. Valid values are `MTO|MTS|ETO|ATO`',
    `reporting_timestamp` TIMESTAMP COMMENT 'Date and time when the scrap event was reported in the MES or ERP system by the operator or automated process. Used for time-series scrap trend analysis and shift-level reporting.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `rework_order_number` STRING COMMENT 'Reference number of the rework production order created to remediate the scrapped item. Populated only when is_rework is true. Enables end-to-end rework cost tracking and yield recovery analysis.',
    `routing_number` STRING COMMENT 'Reference to the production routing used for the order in which the scrap occurred. Enables routing-level scrap analysis to identify process steps with systemic quality issues.',
    `scrap_category` STRING COMMENT 'High-level classification of the scrap event origin: process scrap (inherent process loss), machine scrap (equipment malfunction), material defect (incoming material issue), operator error, design defect, tooling defect, or incoming material. Drives root cause categorization for Six Sigma and CAPA programs.. Valid values are `process_scrap|machine_scrap|material_defect|operator_error|design_defect|tooling_defect|incoming_material`',
    `scrap_cost` DECIMAL(18,2) COMMENT 'Monetary value of the scrapped material calculated using the standard or moving average cost from the material master. Key input for COGS variance analysis, scrap cost reporting, and financial impact assessment of quality failures.. Valid values are `^[0-9]+(.[0-9]{1,2})?$`',
    `scrap_document_number` STRING COMMENT 'Business-facing document number assigned to the scrap event by the source system (SAP PP or Opcenter MES). Used for cross-system traceability and audit purposes.',
    `scrap_quantity` DECIMAL(18,2) COMMENT 'Quantity of material declared as scrap in the base unit of measure. Core metric for scrap rate KPI calculation, COGS variance analysis, and Six Sigma improvement programs.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `scrap_reason_code` STRING COMMENT 'Standardized reason code from the MES or ERP scrap reason catalog describing the specific cause of scrap (e.g., dimensional out-of-tolerance, surface defect, wrong material). Used for Pareto analysis and CAPA prioritization.',
    `scrap_reason_description` STRING COMMENT 'Free-text description providing additional context for the scrap reason beyond the standardized code. Captures operator observations and nuanced failure details for quality investigations.',
    `shift_code` STRING COMMENT 'Production shift identifier during which the scrap event occurred (e.g., Day, Afternoon, Night). Enables shift-level scrap rate benchmarking and operator performance analysis.',
    `source_system` STRING COMMENT 'Identifies the originating operational system that generated the scrap record: SAP S/4HANA PP, Siemens Opcenter MES, or manual entry. Supports data lineage, reconciliation, and audit trail requirements.. Valid values are `SAP_PP|OPCENTER_MES|MANUAL`',
    `unit_of_measure` STRING COMMENT 'Unit of measure for the scrap quantity (e.g., EA for each, KG for kilogram, M for meter). Aligns with SAP base unit of measure for the material.. Valid values are `EA|KG|G|LB|M|M2|M3|L|PC|SET|ROL|BOX|PAL`',
    `work_center_code` STRING COMMENT 'Code identifying the work center (machine, cell, or production line) where the scrap was generated. Used for work center-level scrap rate KPI reporting and capacity impact analysis.',
    CONSTRAINT pk_scrap_record PRIMARY KEY(`scrap_record_id`)
) COMMENT 'Records of scrap and rework generated during production operations (SAP PP Scrap / Opcenter MES Scrap Reporting). Stores production order reference, operation reference, work center, scrap quantity, scrap reason code, scrap category (process scrap, machine scrap, material defect, operator error), material number, scrap cost, rework flag, rework order reference, and reporting timestamp. Feeds scrap rate KPIs, COGS variance analysis, and quality improvement programs (Six Sigma, CAPA). Distinct from quality NCR records — this captures the production-side scrap event.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`production`.`order_type` (
    `order_type_id` BIGINT COMMENT 'Unique surrogate identifier for each production order type record in the lakehouse silver layer. Serves as the primary key for this reference data entity.',
    `availability_check_rule` STRING COMMENT 'SAP checking rule code that governs how component and capacity availability is verified when creating or releasing production orders of this type. Determines which stock categories and supply elements are considered in the ATP (Available to Promise) check.. Valid values are `^[A-Z0-9]{1,2}$`',
    `batch_classification_required` BOOLEAN COMMENT 'Indicates whether batch classification (assignment of batch characteristics and values) is mandatory for production orders of this type. Relevant for regulated industries and traceability requirements.. Valid values are `true|false`',
    `bom_usage` STRING COMMENT 'SAP BOM usage key (e.g., 1 = Production, 5 = Sales, 6 = Costing) that determines which BOM alternative is selected during production order creation for this order type. Ensures the correct BOM is used for component determination.. Valid values are `^[0-9]{1}$`',
    `capacity_relevance_indicator` BOOLEAN COMMENT 'Indicates whether production orders of this type generate capacity requirements on work centers. When true, orders of this type are included in capacity planning and leveling processes.. Valid values are `true|false`',
    `code` STRING COMMENT 'SAP PP order type key (e.g., PP01, PP02, PI01, RW01, PR01) that uniquely identifies the order type in the source ERP system. Used during production order creation to default processing parameters.. Valid values are `^[A-Z0-9]{2,4}$`',
    `confirmation_control_key` STRING COMMENT 'SAP confirmation control key that defines the confirmation behavior for operations in production orders of this type, including whether milestone confirmations, partial confirmations, or automatic final confirmations are permitted.. Valid values are `^[A-Z0-9]{0,4}$`',
    `controlling_area` STRING COMMENT 'SAP controlling area code associated with this order type, defining the organizational unit within which cost accounting and internal reporting are performed for production orders of this type.. Valid values are `^[A-Z0-9]{1,4}$`',
    `costing_sheet` STRING COMMENT 'SAP overhead costing sheet assigned to this order type, defining the overhead calculation rules (overhead rates, base values, credit objects) applied to production orders for overhead absorption and cost allocation.. Valid values are `^[A-Z0-9]{0,6}$`',
    `costing_variant` STRING COMMENT 'SAP costing variant code (e.g., PPP1, PPP2) assigned to this order type. Determines the valuation approach, cost component structure, and overhead calculation method used for production order cost estimation and actual cost collection.. Valid values are `^[A-Z0-9]{2,6}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this production order type record was first created in the lakehouse silver layer. Used for audit trail and data lineage purposes.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `description` STRING COMMENT 'Full business description of the production order type, explaining its intended use, applicable scenarios, and any special processing rules associated with this type.',
    `goods_issue_indicator` STRING COMMENT 'Defines the component goods issue (GI) method for production orders of this type. Manual requires explicit GI posting; backflush automatically posts GI at confirmation; automatic triggers GI at order release.. Valid values are `manual|backflush|automatic`',
    `goods_receipt_indicator` BOOLEAN COMMENT 'Indicates whether an automatic goods receipt (GR) posting is triggered upon final confirmation of a production order of this type. When true, the finished goods inventory is updated automatically without a separate GR transaction.. Valid values are `true|false`',
    `inspection_type` STRING COMMENT 'SAP QM inspection type code (e.g., 03 for goods receipt from production, 89 for in-process inspection) automatically assigned to inspection lots created for production orders of this type. Drives quality inspection planning and execution.. Valid values are `^[0-9]{2}$`',
    `language_code` STRING COMMENT 'ISO 639-1 two-letter language code for the language in which the order type name and description are maintained. Supports multilingual configuration for multinational manufacturing operations.. Valid values are `^[A-Z]{2}$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this production order type record in the lakehouse silver layer. Supports change tracking, incremental data loads, and audit compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `mrp_relevance_indicator` BOOLEAN COMMENT 'Indicates whether production orders of this type are considered in Material Requirements Planning (MRP) and MRP II runs. When true, open orders of this type reduce net requirements during planning.. Valid values are `true|false`',
    `name` STRING COMMENT 'Short descriptive name of the production order type (e.g., Standard Production Order, Rework Order, Prototype Order, Co-Product Order). Used in UI dropdowns and reporting.',
    `order_category` STRING COMMENT 'SAP internal order category code that classifies the fundamental nature of the order type. Category 10 = PP Production Order, 20 = Process Order (PI), 30 = Inspection Order, 40 = Maintenance Order. Drives system behavior at the lowest level.. Valid values are `10|20|30|40`',
    `order_release_control` STRING COMMENT 'Controls when a production order of this type transitions to Released status. Manual requires explicit user action; automatic_on_creation releases immediately upon order creation; automatic_on_save releases when the order is saved.. Valid values are `manual|automatic_on_creation|automatic_on_save`',
    `order_usage` STRING COMMENT 'Business usage classification of the order type indicating the manufacturing scenario it supports: standard production, rework of non-conforming material, prototype/development builds, co-product manufacturing, disassembly, subcontracting, or repair orders.. Valid values are `standard_production|rework|prototype|co_product|disassembly|subcontracting|repair`',
    `plant_code` STRING COMMENT 'SAP plant code to which this production order type is applicable. Enables plant-specific configuration of order types, supporting multinational operations where different plants may use different order type configurations.. Valid values are `^[A-Z0-9]{4}$`',
    `print_control` STRING COMMENT 'SAP print control key that determines which shop floor documents (traveler, pick list, routing sheet, label) are automatically printed when a production order of this type is created or released.. Valid values are `^[A-Z0-9]{0,4}$`',
    `production_strategy` STRING COMMENT 'Manufacturing production strategy associated with this order type. MTO (Make to Order) produces against a specific sales order; MTS (Make to Stock) produces for inventory; ETO (Engineer to Order) involves custom engineering; ATO (Assemble to Order) assembles from standard components on demand.. Valid values are `MTO|MTS|ETO|ATO`',
    `reference_order_type` STRING COMMENT 'SAP order type code used as the reference template when creating orders of this type. Enables inheritance of default parameters from a base order type, supporting standardized configuration management.. Valid values are `^[A-Z0-9]{0,4}$`',
    `results_analysis_key` STRING COMMENT 'SAP results analysis key assigned to the order type, controlling how work-in-progress (WIP) and reserves for unrealized costs are calculated during period-end closing. Relevant for ETO and long-running production orders.. Valid values are `^[A-Z0-9]{0,6}$`',
    `routing_usage` STRING COMMENT 'SAP routing usage key (e.g., 1 = Production, 3 = Universal) that determines which task list types (routings, reference operation sets) are valid for production orders of this type. Controls routing selection during order creation.. Valid values are `^[0-9]{1,2}$`',
    `scheduling_type` STRING COMMENT 'Determines the scheduling direction applied when creating production orders of this type. Forward scheduling calculates finish date from start; backward scheduling calculates start date from required finish; current_date uses today as the reference point.. Valid values are `forward|backward|current_date|only_capacity`',
    `serial_number_profile` STRING COMMENT 'SAP serial number profile assigned to this order type, controlling whether and when serial numbers must be assigned to finished goods produced under orders of this type. Supports unit-level traceability for high-value or regulated products.. Valid values are `^[A-Z0-9]{0,4}$`',
    `settlement_profile` STRING COMMENT 'SAP settlement profile code that defines the rules for settling production order variances and costs to cost objects (e.g., material stock, cost center, profitability segment). Controls period-end cost settlement behavior.. Valid values are `^[A-Z0-9]{2,6}$`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this production order type configuration was sourced. Supports data lineage tracking and reconciliation in the lakehouse silver layer.. Valid values are `SAP_S4HANA|OPCENTER_MES|MANUAL`',
    `status` STRING COMMENT 'Current lifecycle status of the production order type configuration record. Active types are available for production order creation; inactive types are temporarily disabled; obsolete types are retired and no longer used.. Valid values are `active|inactive|obsolete`',
    `status_profile` STRING COMMENT 'SAP user status profile assigned to this order type, defining the allowed user-defined statuses and permissible status transitions for production orders of this type (e.g., HOLD, QUAL, APPR). Enables differentiated status management beyond standard system statuses.. Valid values are `^[A-Z0-9]{0,7}$`',
    `valid_from_date` DATE COMMENT 'Date from which this production order type configuration is effective and available for use in production order creation. Supports time-dependent configuration management.. Valid values are `^d{4}-d{2}-d{2}$`',
    `valid_to_date` DATE COMMENT 'Date until which this production order type configuration remains effective. After this date, the order type is no longer available for new production order creation. Supports planned configuration transitions.. Valid values are `^d{4}-d{2}-d{2}$`',
    `variance_key` STRING COMMENT 'SAP variance key assigned to this order type, controlling which variance categories (input price, quantity, resource-usage, output price, mixed-price, remaining) are calculated during period-end variance analysis for production orders.. Valid values are `^[A-Z0-9]{0,6}$`',
    `wip_calculation_method` STRING COMMENT 'Defines the method used to calculate Work In Progress (WIP) value for production orders of this type during period-end closing. Target cost uses standard cost; actual cost uses confirmed actual costs; none excludes WIP calculation.. Valid values are `target_cost|actual_cost|none`',
    CONSTRAINT pk_order_type PRIMARY KEY(`order_type_id`)
) COMMENT 'Reference data defining the types of production orders used in manufacturing operations (SAP PP Order Type). Stores order type code, order type description, production strategy (MTO, MTS, ETO, ATO), settlement rule, costing variant, scheduling type (forward, backward, current date), availability check rule, goods receipt indicator, and applicable plant. Drives default behavior for production order creation and processing. Enables differentiated handling of standard production, rework orders, prototype orders, and co-product orders.';

