ALTER TABLE `manufacturing_ecm`.`production`.`planned_order` ADD CONSTRAINT `fk_production_planned_order_routing_id` FOREIGN KEY (`routing_id`) REFERENCES `manufacturing_ecm`.`production`.`routing`(`routing_id`);
